def _decode_json_dict(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return value

    if value in {None, "", "{}"}:
        return {}

    try:
        decoded = json.loads(value)
    except Exception:
        return {}

    if isinstance(decoded, dict):
        return decoded

    return {}

def print_netsniper_intelligence_summary(row: sqlite3.Row | None) -> None:
    if row is None:
        print("No NetSniper v1.7 intelligence summary has been imported yet.")
        return

    print(f"Scan ID:                    {row['scan_id']}")
    print(f"Hosts:                      {row['host_count']}")
    print(f"Classified:                 {row['classified_count']}")
    print(f"Possible / review:          {row['possible_or_review_count']}")
    print(f"Unknown:                    {row['unknown_count']}")
    print(f"Contradiction hosts:         {row['contradiction_host_count']}")
    print(f"False-confidence candidates: {row['false_confidence_candidate_count']}")
    print(f"Unknown exposed services:    {row['unknown_with_exposed_services_count']}")
    print()
    print("Top device types:")

    top_types = _decode_json_dict(row["top_device_types_json"])
    if not top_types:
        print("  None recorded.")
    else:
        for name, count in top_types.items():
            print(f"  {name}: {count}")

    print()
    print("Confidence bands:")
    bands = _decode_json_dict(row["confidence_band_counts_json"])
    if not bands:
        print("  None recorded.")
    else:
        for name, count in bands.items():
            print(f"  {name}: {count}")

    print()
    print("Review queue sample:")
    review = _decode_json_list(row["review_queue_json"])
    if not review:
        print("  No review queue items.")
    else:
        for item in review[:10]:
            identity = item.get("identity") or item.get("ip") or item.get("host_id") or "unknown"
            classification = item.get("primary_type") or item.get("classification") or "Unknown"
            confidence = item.get("confidence", 0)
            decision = item.get("decision", "unknown")
            reason = item.get("reason") or item.get("siem_action") or "review"
            print(f"  {identity} | {classification} | confidence={confidence} | decision={decision} | reason={reason}")


def command_intelligence(args: argparse.Namespace) -> int:
    connection = connect(args.db)
    row = latest_netsniper_intelligence_summary(connection)
    print_netsniper_intelligence_summary(row)
    return 0


def snapshot_exists(connection: sqlite3.Connection, scan_id: str) -> bool:
    return connection.execute("SELECT 1 FROM snapshots WHERE scan_id = ?", (scan_id,)).fetchone() is not None


def latest_accepted_snapshot(connection: sqlite3.Connection, target: str) -> sqlite3.Row | None:
    network_scope = canonical_network_scope(target)

    return connection.execute(
        """
        SELECT *
        FROM snapshots
        WHERE network_scope = ?
          AND quality_status = 'ACCEPTED'
        ORDER BY created_at DESC, imported_at DESC
        LIMIT 1
        """,
        (network_scope,),
    ).fetchone()

def assess_quality(snapshot: Snapshot, baseline: sqlite3.Row | None) -> tuple[str, str]:
    if snapshot.bundle_status != "COMPLETE":
        return "REJECTED", "NetSniper bundle status is not COMPLETE."
    if snapshot.bundle_deltaaegis_ready is False:
        return "REJECTED", "NetSniper bundle quality is not DeltaAegis-ready."
    if snapshot.xml_exit_status != "success":
        return "REJECTED", f"Nmap XML exit status is {snapshot.xml_exit_status!r}, not 'success'."
    if snapshot.hosts_up <= 0 or not snapshot.assets:
        return "REVIEW_REQUIRED", "Snapshot contains no usable live assets."
    if baseline is not None:
        prior_hosts = int(baseline["hosts_up"])
        if prior_hosts > 0 and snapshot.hosts_up < prior_hosts * QUALITY_RATIO_THRESHOLD:
            return "REVIEW_REQUIRED", f"Host count dropped from {prior_hosts} to {snapshot.hosts_up}; snapshot requires review."
        prior_coverage = float(baseline["identity_coverage"])
        if prior_coverage >= IDENTITY_COVERAGE_THRESHOLD and snapshot.identity_coverage < IDENTITY_DROP_REVIEW_THRESHOLD:
            return "REVIEW_REQUIRED", f"MAC-backed identity coverage dropped from {prior_coverage:.0%} to {snapshot.identity_coverage:.0%}."
        old_fp = str(baseline["profile_fingerprint"] or "")
        if str(baseline["manifest_schema_version"]) in NETSNIPER_PROFILE_AWARE_SCHEMAS and snapshot.manifest_schema_version in NETSNIPER_PROFILE_AWARE_SCHEMAS and old_fp and old_fp != snapshot.profile_fingerprint:
            return "REVIEW_REQUIRED", "NetSniper scan profile fingerprint changed. Approve a new baseline before comparing monitored services."
    return "ACCEPTED", "Snapshot passed quality checks."


def insert_snapshot(connection: sqlite3.Connection, snapshot: Snapshot, quality_status: str, quality_reason: str) -> None:
    connection.execute(
        """INSERT INTO snapshots (
            scan_id, manifest_path, target, network_scope, scanner_version,
            scan_profile, created_at, imported_at, bundle_status,
            quality_status, quality_reason, xml_exit_status, hosts_up,
            hosts_down, hosts_total, mac_backed_assets, identity_coverage,
            is_accepted_baseline, manifest_schema_version, profile_fingerprint,
            monitored_ports_json, protocols_json, discovery_interface,
            nmap_version, scan_started_at, scan_completed_at,
            neighbors_captured_at, requested_profile, effective_profile,
            profile_contract, profile_runtime_budget_seconds,
            profile_host_timeout_seconds, profile_duration_seconds,
            profile_budget_exceeded, bundle_quality_schema_version,
            bundle_deltaaegis_ready, bundle_quality_json
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
        (
            snapshot.scan_id,
            snapshot.manifest_path,
            snapshot.target,
            snapshot_network_scope(snapshot),
            snapshot.scanner_version,
            snapshot.scan_profile,
            snapshot.created_at,
            utc_now(),
            snapshot.bundle_status,
            quality_status,
            quality_reason,
            snapshot.xml_exit_status,
            snapshot.hosts_up,
            snapshot.hosts_down,
            snapshot.hosts_total,
            snapshot.mac_backed_assets,
            snapshot.identity_coverage,
            1 if quality_status == "ACCEPTED" else 0,
            snapshot.manifest_schema_version,
            snapshot.profile_fingerprint,
            json.dumps(snapshot.monitored_ports),
            json.dumps(snapshot.protocols),
            snapshot.discovery_interface,
            snapshot.nmap_version,
            snapshot.scan_started_at,
            snapshot.scan_completed_at,
            snapshot.neighbors_captured_at,
            snapshot.requested_profile,
            snapshot.effective_profile,
            snapshot.profile_contract,
            snapshot.profile_runtime_budget_seconds,
            snapshot.profile_host_timeout_seconds,
            snapshot.profile_duration_seconds,
            (
                (1 if snapshot.profile_budget_exceeded else 0)
                if snapshot.profile_budget_exceeded is not None
                else None
            ),
            snapshot.bundle_quality_schema_version,
            (
                (1 if snapshot.bundle_deltaaegis_ready else 0)
                if snapshot.bundle_deltaaegis_ready is not None
                else None
            ),
            snapshot.bundle_quality_json,
        ),
    )
    for asset in snapshot.assets.values():
        connection.execute(
            """INSERT INTO asset_observations (
                scan_id,
                asset_key,
                identity_class,
                identity_confidence,
                identity_source,
                ip_address,
                mac_address,
                vendor,
                hostname,
                device_type,
                device_type_confidence,
                classification_type,
                classification_primary_type,
                classification_confidence,
                classification_confidence_label,
                classification_decision,
                classification_method,
                classification_json,
                classification_evidence_json,
                classification_contradictions_json,
                classification_candidates_json,
                  classification_confidence_band,
                  classification_calibrated_decision,
                  classification_siem_action,
                  classification_calibration_reason,
                  classification_validation_state,
                  classification_contradiction_count,
                  classification_validator_summary_json,
                  classification_validators_json,
                  severity,
                  score
              ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (
                snapshot.scan_id,
                asset.asset_key,
                asset.identity_class,
                asset.identity_confidence,
                asset.identity_source,
                asset.ip_address,
                asset.mac_address,
                asset.vendor,
                asset.hostname,
                asset.device_type,
                asset.device_type_confidence,
                asset.classification_type,
                asset.classification_primary_type,
                asset.classification_confidence,
                asset.classification_confidence_label,
                asset.classification_decision,
                asset.classification_method,
                asset.classification_json,
                asset.classification_evidence_json,
                asset.classification_contradictions_json,
                asset.classification_candidates_json,
                  asset.classification_confidence_band,
                  asset.classification_calibrated_decision,
                  asset.classification_siem_action,
                  asset.classification_calibration_reason,
                  asset.classification_validation_state,
                  asset.classification_contradiction_count,
                  asset.classification_validator_summary_json,
                  asset.classification_validators_json,
                  asset.severity,
                  asset.score,
            ),
        )
        for service in asset.services:
            connection.execute("""INSERT INTO service_observations (scan_id, asset_key, protocol, port, state, service_name, product, version) VALUES (?, ?, ?, ?, ?, ?, ?, ?)""", (snapshot.scan_id, asset.asset_key, service.protocol, service.port, service.state, service.service_name, service.product, service.version))
        for finding in asset.findings:
            connection.execute("""INSERT OR IGNORE INTO finding_observations (scan_id, asset_key, finding_id, name, service, port, score, evidence) VALUES (?, ?, ?, ?, ?, ?, ?, ?)""", (snapshot.scan_id, asset.asset_key, str(finding.get("finding_id", finding.get("id", "UNKNOWN"))), finding.get("name"), finding.get("service"), int(finding.get("port", -1)), finding.get("score"), finding.get("evidence")))


def load_assets_from_db(connection: sqlite3.Connection, scan_id: str) -> dict[str, AssetObservation]:
    assets: dict[str, AssetObservation] = {}
    rows = connection.execute("SELECT * FROM asset_observations WHERE scan_id = ?", (scan_id,)).fetchall()
    for row in rows:
        services = [Service(item["protocol"], item["port"], item["state"], item["service_name"], item["product"], item["version"]) for item in connection.execute("SELECT * FROM service_observations WHERE scan_id = ? AND asset_key = ? ORDER BY protocol, port", (scan_id, row["asset_key"]))]
        findings = [dict(item) for item in connection.execute("SELECT * FROM finding_observations WHERE scan_id = ? AND asset_key = ?", (scan_id, row["asset_key"]))]
        assets[row["asset_key"]] = AssetObservation(
            row["asset_key"],
            row["identity_class"],
            row["identity_confidence"],
            row["identity_source"],
            row["ip_address"],
            row["mac_address"],
            row["vendor"],
            row["hostname"],
            row["device_type"],
            row["severity"],
            row["score"],
            services,
            findings,
            device_type_confidence=row["device_type_confidence"],
            classification_type=row["classification_type"],
            classification_primary_type=row["classification_primary_type"],
            classification_confidence=row["classification_confidence"],
            classification_confidence_label=row["classification_confidence_label"],
            classification_decision=row["classification_decision"],
            classification_method=row["classification_method"],
            classification_json=row["classification_json"],
            classification_evidence_json=row["classification_evidence_json"],
            classification_contradictions_json=row["classification_contradictions_json"],
            classification_candidates_json=row["classification_candidates_json"],
            classification_confidence_band=row["classification_confidence_band"],
            classification_calibrated_decision=row["classification_calibrated_decision"],
            classification_siem_action=row["classification_siem_action"],
            classification_calibration_reason=row["classification_calibration_reason"],
            classification_validation_state=row["classification_validation_state"],
            classification_contradiction_count=row["classification_contradiction_count"],
            classification_validator_summary_json=row["classification_validator_summary_json"],
            classification_validators_json=row["classification_validators_json"],
        )
    return assets


def event(event_type: str, severity: str, subject_key: str, summary: str, previous_value: Any = None, current_value: Any = None) -> dict[str, Any]:
    return {"event_type": event_type, "severity": severity, "subject_key": subject_key, "summary": summary, "previous_value": previous_value, "current_value": current_value}


def reset_lifecycle(
    connection: sqlite3.Connection,
    scan_id: str,
    created_at: str,
    assets: dict[str, AssetObservation],
    network_scope: str,
) -> None:
    connection.execute(
        "DELETE FROM asset_lifecycle WHERE network_scope = ?",
        (network_scope,),
    )

    for asset in assets.values():
        connection.execute(
            """
            INSERT INTO asset_lifecycle (
                network_scope,
                asset_key,
                identity_class,
                state,
                missing_count,
                current_ip,
                mac_address,
                vendor,
                hostname,
                first_seen_scan_id,
                last_seen_scan_id,
                first_seen_at,
                last_seen_at,
                removed_at
            )
            VALUES (?, ?, ?, 'ACTIVE', 0, ?, ?, ?, ?, ?, ?, ?, ?, NULL)
            """,
            (
                network_scope,
                asset.asset_key,
                asset.identity_class,
                asset.ip_address,
                asset.mac_address,
                asset.vendor,
                asset.hostname,
                scan_id,
                scan_id,
                created_at,
                created_at,
            ),
        )

def initialize_lifecycle(connection: sqlite3.Connection, snapshot: Snapshot) -> None:
    reset_lifecycle(
        connection,
        snapshot.scan_id,
        snapshot.created_at,
        snapshot.assets,
        snapshot_network_scope(snapshot),
    )

def lifecycle_events(connection: sqlite3.Connection, snapshot: Snapshot) -> list[dict[str, Any]]:
    events: list[dict[str, Any]] = []
    network_scope = snapshot_network_scope(snapshot)

    existing = {
        row["asset_key"]: row
        for row in connection.execute(
            "SELECT * FROM asset_lifecycle WHERE network_scope = ?",
            (network_scope,),
        )
    }

    current_keys = set(snapshot.assets)

    for key, asset in snapshot.assets.items():
        row = existing.get(key)

        if row is None:
            if asset.identity_class == "GLOBAL_MAC":
                events.append(event("ASSET_FIRST_OBSERVED", "MEDIUM", key, f"Asset {key} was observed for the first time at {asset.ip_address}."))
            elif asset.identity_class == "LOCAL_MAC":
                events.append(event("EPHEMERAL_IDENTITY_FIRST_OBSERVED", "INFO", key, f"Locally administered identity {key} was observed at {asset.ip_address}."))
            else:
                events.append(event("IP_FIRST_OBSERVED", "LOW", key, f"IP address {asset.ip_address} was observed for the first time."))

            connection.execute(
                """
                INSERT INTO asset_lifecycle (
                    network_scope,
                    asset_key,
                    identity_class,
                    state,
                    missing_count,
                    current_ip,
                    mac_address,
                    vendor,
                    hostname,
                    first_seen_scan_id,
                    last_seen_scan_id,
                    first_seen_at,
                    last_seen_at,
                    removed_at
                )
                VALUES (?, ?, ?, 'ACTIVE', 0, ?, ?, ?, ?, ?, ?, ?, ?, NULL)
                """,
                (
                    network_scope,
                    key,
                    asset.identity_class,
                    asset.ip_address,
                    asset.mac_address,
                    asset.vendor,
                    asset.hostname,
                    snapshot.scan_id,
                    snapshot.scan_id,
                    snapshot.created_at,
                    snapshot.created_at,
                ),
            )
            continue

        if row["state"] != "ACTIVE":
            if asset.identity_class == "GLOBAL_MAC":
                events.append(event("ASSET_REAPPEARED", "INFO", key, f"Asset {key} reappeared at {asset.ip_address}."))
            elif asset.identity_class == "LOCAL_MAC":
                events.append(event("EPHEMERAL_IDENTITY_REAPPEARED", "INFO", key, f"Locally administered identity {key} reappeared at {asset.ip_address}."))
            else:
                events.append(event("IP_REAPPEARED", "INFO", key, f"IP address {asset.ip_address} reappeared."))

        if asset.identity_class == "GLOBAL_MAC" and row["current_ip"] != asset.ip_address:
            events.append(event("IP_CHANGED", "INFO", key, f"Asset {key} changed IP address from {row['current_ip']} to {asset.ip_address}.", row["current_ip"], asset.ip_address))

        connection.execute(
            """
            UPDATE asset_lifecycle
            SET
                identity_class = ?,
                state = 'ACTIVE',
                missing_count = 0,
                current_ip = ?,
                mac_address = ?,
                vendor = COALESCE(?, vendor),
                hostname = COALESCE(?, hostname),
                last_seen_scan_id = ?,
                last_seen_at = ?,
                removed_at = NULL
            WHERE network_scope = ?
              AND asset_key = ?
            """,
            (
                asset.identity_class,
                asset.ip_address,
                asset.mac_address,
                asset.vendor,
                asset.hostname,
                snapshot.scan_id,
                snapshot.created_at,
                network_scope,
                key,
            ),
        )

    for key, row in existing.items():
        if key in current_keys:
            continue

        missing_count = int(row["missing_count"]) + 1

        if row["identity_class"] == "LOCAL_MAC":
            if row["state"] == "ACTIVE":
                events.append(event("EPHEMERAL_IDENTITY_NOT_OBSERVED", "INFO", key, f"Locally administered identity {key} was not observed in the current accepted snapshot. Last known IP: {row['current_ip']}."))

            connection.execute(
                """
                UPDATE asset_lifecycle
                SET state = 'EPHEMERAL_MISSING',
                    missing_count = ?
                WHERE network_scope = ?
                  AND asset_key = ?
                """,
                (missing_count, network_scope, key),
            )

        elif row["identity_class"] == "GLOBAL_MAC":
            if row["state"] == "ACTIVE":
                events.append(event("ASSET_NOT_OBSERVED", "LOW", key, f"Previously observed asset {key} was not observed in the current accepted snapshot. Last known IP: {row['current_ip']}."))
                connection.execute(
                    """
                    UPDATE asset_lifecycle
                    SET state = 'MISSING',
                        missing_count = ?
                    WHERE network_scope = ?
                      AND asset_key = ?
                    """,
                    (missing_count, network_scope, key),
                )
            elif row["state"] != "REMOVED" and missing_count >= REMOVAL_THRESHOLD:
                events.append(event("ASSET_REMOVED", "MEDIUM", key, f"Asset {key} has not been observed in {REMOVAL_THRESHOLD} consecutive accepted snapshots. Last known IP: {row['current_ip']}."))
                connection.execute(
                    """
                    UPDATE asset_lifecycle
                    SET state = 'REMOVED',
                        missing_count = ?,
                        removed_at = ?
                    WHERE network_scope = ?
                      AND asset_key = ?
                    """,
                    (missing_count, snapshot.created_at, network_scope, key),
                )
            elif row["state"] != "REMOVED":
                connection.execute(
                    """
                    UPDATE asset_lifecycle
                    SET missing_count = ?
                    WHERE network_scope = ?
                      AND asset_key = ?
                    """,
                    (missing_count, network_scope, key),
                )
        else:
            if row["state"] == "ACTIVE":
                events.append(event("IP_NOT_OBSERVED", "LOW", key, f"Previously observed IP address {row['current_ip']} was not observed in the current accepted snapshot."))

            connection.execute(
                """
                UPDATE asset_lifecycle
                SET state = 'MISSING',
                    missing_count = ?
                WHERE network_scope = ?
                  AND asset_key = ?
                """,
                (missing_count, network_scope, key),
            )

    return events


def _decode_json_list(value: str | None) -> list[Any]:
    if not value:
        return []
    try:
        decoded = json.loads(value)
    except (TypeError, json.JSONDecodeError):
        return []
    return decoded if isinstance(decoded, list) else []


def _classification_type(asset: AssetObservation) -> str:
    return str(asset.classification_type or asset.classification_primary_type or "").strip()


def _classification_decision(asset: AssetObservation) -> str:
    decision = str(asset.classification_decision or "").strip().lower()
    if decision:
        return decision

    # Backward compatibility for early NetSniper v1.4-dev bundles that stored
    # classification confidence/type but did not yet include classification.decision.
    confidence = _classification_confidence(asset)

    if confidence >= 40:
        return "classified"
    if confidence > 0:
        return "possible"
    return "unknown"


def _classification_confidence(asset: AssetObservation) -> int:
    return int(asset.classification_confidence or asset.device_type_confidence or 0)


def _has_classification_intelligence(asset: AssetObservation) -> bool:
    # Important: this must check raw stored NetSniper v1.4 fields only.
    # Do not call _classification_decision() here, because that helper infers
    # a decision for backward compatibility. Older pre-v1.4 snapshots should
    # not be treated as classification-aware baselines.
    return bool(
        asset.classification_type
        or asset.classification_primary_type
        or asset.classification_decision
        or asset.classification_method
        or asset.classification_confidence is not None
        or asset.device_type_confidence is not None
        or asset.classification_json not in {None, "", "{}"}
        or asset.classification_evidence_json not in {None, "", "[]"}
        or asset.classification_contradictions_json not in {None, "", "[]"}
        or asset.classification_candidates_json not in {None, "", "[]"}
        or asset.classification_confidence_band
        or asset.classification_calibrated_decision
        or asset.classification_siem_action
        or asset.classification_calibration_reason
        or asset.classification_validation_state
        or asset.classification_contradiction_count is not None
        or asset.classification_validator_summary_json not in {None, "", "{}"}
        or asset.classification_validators_json not in {None, "", "[]"}
    )


def _classification_snapshot(asset: AssetObservation) -> dict[str, Any]:
    evidence = _decode_json_list(asset.classification_evidence_json)
    contradictions = _decode_json_list(asset.classification_contradictions_json)
    candidates = _decode_json_list(asset.classification_candidates_json)
    validators = _decode_json_list(asset.classification_validators_json)

    validator_summary = {}
    try:
        decoded_summary = json.loads(asset.classification_validator_summary_json or "{}")
        if isinstance(decoded_summary, dict):
            validator_summary = decoded_summary
    except (TypeError, json.JSONDecodeError):
        validator_summary = {}

    return {
        "ip_address": asset.ip_address,
        "device_type": asset.device_type,
        "device_type_confidence": asset.device_type_confidence,
        "classification_type": _classification_type(asset) or None,
        "classification_primary_type": asset.classification_primary_type,
        "classification_confidence": _classification_confidence(asset),
        "classification_confidence_label": asset.classification_confidence_label,
        "classification_decision": _classification_decision(asset) or None,
        "classification_method": asset.classification_method,
        "classification_confidence_band": asset.classification_confidence_band,
        "classification_calibrated_decision": asset.classification_calibrated_decision,
        "classification_siem_action": asset.classification_siem_action,
        "classification_calibration_reason": asset.classification_calibration_reason,
        "classification_validation_state": asset.classification_validation_state,
        "evidence_count": len(evidence),
        "contradiction_count": (
            asset.classification_contradiction_count
            if asset.classification_contradiction_count is not None
            else len(contradictions)
        ),
        "candidate_count": len(candidates),
        "validator_count": len(validators),
        "validator_summary": validator_summary,
    }


def classification_delta_events(previous: dict[str, AssetObservation], current: dict[str, AssetObservation]) -> list[dict[str, Any]]:
    events: list[dict[str, Any]] = []

    for key, new_asset in sorted(current.items()):
        old_asset = previous.get(key)
        if old_asset is None:
            continue

        # Avoid flooding when the baseline was produced before NetSniper v1.4.
        if not _has_classification_intelligence(old_asset) or not _has_classification_intelligence(new_asset):
            continue

        old_type = _classification_type(old_asset)
        new_type = _classification_type(new_asset)
        old_decision = _classification_decision(old_asset)
        new_decision = _classification_decision(new_asset)
        old_confidence = _classification_confidence(old_asset)
        new_confidence = _classification_confidence(new_asset)

        previous_value = _classification_snapshot(old_asset)
        current_value = _classification_snapshot(new_asset)

        if old_type != new_type and (old_decision != "unknown" or new_decision != "unknown"):
            severity = "MEDIUM" if new_decision == "classified" else "LOW"
            events.append(event(
                "DEVICE_CLASSIFICATION_CHANGED",
                severity,
                key,
                (
                    f"NetSniper classification for {key} changed from "
                    f"{old_type or 'Unknown'} ({old_confidence}) to "
                    f"{new_type or 'Unknown'} ({new_confidence})."
                ),
                previous_value,
                current_value,
            ))

        confidence_delta = abs(new_confidence - old_confidence)
        decision_changed = old_decision != new_decision

        if old_type == new_type and (decision_changed or confidence_delta >= 20):
            severity = "MEDIUM" if decision_changed and new_decision == "classified" else "INFO"
            events.append(event(
                "DEVICE_CLASSIFICATION_CONFIDENCE_CHANGED",
                severity,
                key,
                (
                    f"NetSniper classification confidence for {key} changed from "
                    f"{old_confidence} ({old_decision or 'unknown'}) to "
                    f"{new_confidence} ({new_decision or 'unknown'}) for "
                    f"{new_type or 'Unknown'}."
                ),
                previous_value,
                current_value,
            ))

        if new_decision == "possible" and old_decision != "possible":
            severity = "MEDIUM" if old_decision == "classified" else "LOW"
            events.append(event(
                "DEVICE_CLASSIFICATION_WEAK",
                severity,
                key,
                (
                    f"NetSniper classification for {key} is now weak/possible: "
                    f"{new_type or 'Unknown'} at confidence {new_confidence}."
                ),
                previous_value,
                current_value,
            ))

        old_contradictions = _decode_json_list(old_asset.classification_contradictions_json)
        new_contradictions = _decode_json_list(new_asset.classification_contradictions_json)

        if new_contradictions and new_contradictions != old_contradictions:
            events.append(event(
                "DEVICE_CLASSIFICATION_CONTRADICTION",
                "MEDIUM",
                key,
                (
                    f"NetSniper reported classification contradiction(s) for {key}: "
                    f"{len(new_contradictions)} contradiction(s) present."
                ),
                previous_value,
                current_value,
            ))

    return events

def comparison_events(previous: dict[str, AssetObservation], current: dict[str, AssetObservation]) -> list[dict[str, Any]]:
    events: list[dict[str, Any]] = []
    for key in sorted(set(previous) & set(current)):
        old_asset, new_asset = previous[key], current[key]
        old_services = {service.key: service for service in old_asset.services}
        new_services = {service.key: service for service in new_asset.services}
        for service_key in sorted(set(new_services) - set(old_services)):
            service = new_services[service_key]
            events.append(event("MONITORED_SERVICE_OPENED", "MEDIUM", key, f"A newly observed monitored service appeared on {new_asset.ip_address}: {service.protocol}/{service.port}.", current_value=asdict(service)))
        for service_key in sorted(set(old_services) - set(new_services)):
            service = old_services[service_key]
            events.append(event("MONITORED_SERVICE_CLOSED", "INFO", key, f"A previously observed monitored service disappeared from {old_asset.ip_address}: {service.protocol}/{service.port}.", previous_value=asdict(service)))
        old_findings = {(str(item.get("finding_id", item.get("id", "UNKNOWN"))), int(item.get("port", -1))) for item in old_asset.findings}
        new_findings = {(str(item.get("finding_id", item.get("id", "UNKNOWN"))), int(item.get("port", -1))) for item in new_asset.findings}
        for finding_id, port in sorted(new_findings - old_findings):
            events.append(event("NETSNIPER_FINDING_ADDED", "MEDIUM", key, f"NetSniper reported a new interpreted finding on {new_asset.ip_address}: {finding_id} (port {port}).", current_value={"finding_id": finding_id, "port": port}))
        for finding_id, port in sorted(old_findings - new_findings):
            events.append(event("NETSNIPER_FINDING_REMOVED", "INFO", key, f"A previously reported NetSniper finding is no longer present on {old_asset.ip_address}: {finding_id} (port {port}).", previous_value={"finding_id": finding_id, "port": port}))
    return events


def alert_dedup_key(item: dict[str, Any]) -> str | None:
    etype = item["event_type"]
    subject = item["subject_key"]
    value = item.get("current_value") or item.get("previous_value") or {}
    if etype in {"MONITORED_SERVICE_OPENED", "MONITORED_SERVICE_CLOSED"}:
        return f"service:{subject}:{value.get('protocol')}:{value.get('port')}"
    if etype in {"NETSNIPER_FINDING_ADDED", "NETSNIPER_FINDING_REMOVED"}:
        return f"finding:{subject}:{value.get('finding_id')}:{value.get('port')}"
    if etype in {"ASSET_FIRST_OBSERVED", "ASSET_REMOVED", "ASSET_REAPPEARED"}:
        return f"asset:{subject}"
    if etype in {"SNAPSHOT_REVIEW_REQUIRED", "SNAPSHOT_PROFILE_CHANGED"}:
        return f"snapshot:{subject}"
    return None


def sync_alert(connection: sqlite3.Connection, item: dict[str, Any], event_id: int, created_at: str) -> None:
    key = alert_dedup_key(item)
    if key is None:
        return
    etype = item["event_type"]
    if etype in {"MONITORED_SERVICE_CLOSED", "NETSNIPER_FINDING_REMOVED", "ASSET_REAPPEARED"}:
        connection.execute("UPDATE alerts SET status = 'RESOLVED', resolved_at = ?, last_seen_at = ?, last_event_id = ? WHERE dedup_key = ? AND status != 'RESOLVED'", (created_at, created_at, event_id, key))
        return
    connection.execute("""INSERT INTO alerts (dedup_key, event_type, severity, subject_key, status, summary, opened_at, last_seen_at, first_event_id, last_event_id) VALUES (?, ?, ?, ?, 'OPEN', ?, ?, ?, ?, ?) ON CONFLICT(dedup_key) DO UPDATE SET event_type=excluded.event_type, severity=excluded.severity, subject_key=excluded.subject_key, summary=excluded.summary, last_seen_at=excluded.last_seen_at, last_event_id=excluded.last_event_id, status=CASE WHEN alerts.status='RESOLVED' THEN 'OPEN' ELSE alerts.status END, resolved_at=CASE WHEN alerts.status='RESOLVED' THEN NULL ELSE alerts.resolved_at END""", (key, etype, item["severity"], item["subject_key"], item["summary"], created_at, created_at, event_id, event_id))


def store_events(connection: sqlite3.Connection, scan_id: str, baseline_scan_id: str | None, events: Iterable[dict[str, Any]], export_path: Path) -> int:
    export_path.parent.mkdir(parents=True, exist_ok=True)
    count = 0
    with export_path.open("a", encoding="utf-8") as handle:
        for item in events:
            created_at = utc_now()
            cursor = connection.execute("""INSERT INTO delta_events (scan_id, baseline_scan_id, event_type, severity, subject_key, previous_value, current_value, summary, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)""", (scan_id, baseline_scan_id, item["event_type"], item["severity"], item["subject_key"], json.dumps(item.get("previous_value"), sort_keys=True), json.dumps(item.get("current_value"), sort_keys=True), item["summary"], created_at))
            sync_alert(connection, item, int(cursor.lastrowid), created_at)
            handle.write(json.dumps({"scan_id": scan_id, "baseline_scan_id": baseline_scan_id, "created_at": created_at, **item}, sort_keys=True) + "\n")
            count += 1
    return count


def identity_transition(previous_coverage: float, current_coverage: float) -> bool:
    return previous_coverage < IDENTITY_COVERAGE_THRESHOLD <= current_coverage


def profile_transition(baseline: sqlite3.Row, snapshot: Snapshot) -> bool:
    return str(baseline["manifest_schema_version"]) not in NETSNIPER_PROFILE_AWARE_SCHEMAS and snapshot.manifest_schema_version in NETSNIPER_PROFILE_AWARE_SCHEMAS


def ingest_manifest(connection: sqlite3.Connection, manifest_path: Path, export_path: Path) -> str:
    snapshot = load_snapshot(manifest_path)
    if snapshot_exists(connection, snapshot.scan_id):
        return f"SKIP {snapshot.scan_id}: already imported"
    baseline = latest_accepted_snapshot(connection, snapshot.target)
    quality_status, quality_reason = assess_quality(snapshot, baseline)
    insert_snapshot(connection, snapshot, quality_status, quality_reason)
    manifest_data = load_json_file(manifest_path, {})
    if not isinstance(manifest_data, dict):
        manifest_data = {}
    store_netsniper_intelligence_summary(connection, snapshot, manifest_path, manifest_data)
    store_netsniper_intelligence_hosts(connection, snapshot, manifest_path, manifest_data)
    events: list[dict[str, Any]] = []
    if quality_status == "ACCEPTED":
        if baseline is None:
            initialize_lifecycle(connection, snapshot)
        elif profile_transition(baseline, snapshot):
            initialize_lifecycle(connection, snapshot)
            events.append(event("PROFILE_BASELINE_RESET", "INFO", f"scan:{snapshot.scan_id}", "NetSniper telemetry contract upgraded to a profile-aware manifest. This snapshot becomes the new profile baseline without generating service-change deltas."))
        elif identity_transition(float(baseline["identity_coverage"]), snapshot.identity_coverage):
            initialize_lifecycle(connection, snapshot)
            events.append(event("IDENTITY_BASELINE_RESET", "INFO", f"scan:{snapshot.scan_id}", f"MAC-backed identity coverage increased from {float(baseline['identity_coverage']):.0%} to {snapshot.identity_coverage:.0%}. This snapshot becomes the new identity baseline without generating asset-change deltas."))
        else:
            previous_assets = load_assets_from_db(connection, baseline["scan_id"])
            events.extend(comparison_events(previous_assets, snapshot.assets))
            events.extend(classification_delta_events(previous_assets, snapshot.assets))
            events.extend(lifecycle_events(connection, snapshot))
    else:
        etype = "SNAPSHOT_PROFILE_CHANGED" if "profile fingerprint changed" in quality_reason.lower() else "SNAPSHOT_REVIEW_REQUIRED"
        events.append(event(etype, "MEDIUM", f"scan:{snapshot.scan_id}", quality_reason))
    event_count = store_events(connection, snapshot.scan_id, baseline["scan_id"] if baseline else None, events, export_path)
    connection.commit()
    return f"IMPORT {snapshot.scan_id}: quality={quality_status}, assets={len(snapshot.assets)}, mac_identity={snapshot.identity_coverage:.0%}, events={event_count}"


def finalized_manifests(runs_dir: Path) -> list[Path]:
    if not runs_dir.is_dir():
        raise DeltaAegisError(f"NetSniper runs directory does not exist: {runs_dir}")
    return sorted(runs_dir.glob("*/manifest.json"))


def command_ingest(args: argparse.Namespace) -> int:
    connection = connect(args.db)
    manifests = finalized_manifests(args.runs_dir)
    if not manifests:
        print(f"No finalized NetSniper telemetry bundles found under {args.runs_dir}")
        return 0
    for manifest in manifests:
        try:
            print(ingest_manifest(connection, manifest, args.events))
        except DeltaAegisError as exc:
            print(f"ERROR {manifest}: {exc}", file=sys.stderr)
    return 0



def utc_now_text() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat()


def validate_private_cidr(target: str) -> str:
    raw = (target or "").strip()

    if not raw:
        raise DeltaAegisError("target CIDR is required")

    try:
        network = ipaddress.ip_network(raw, strict=False)
    except ValueError as exc:
        raise DeltaAegisError(f"invalid target CIDR: {raw}") from exc

    if network.version != 4:
        raise DeltaAegisError("only IPv4 CIDR targets are supported")

    if not network.is_private:
        raise DeltaAegisError("target must be a private IPv4 CIDR")

    return str(network)


ALLOWED_NETSNIPER_SCAN_PROFILES = {"quick", "balanced", "accurate"}


def validate_netsniper_scan_profile(profile: str | None) -> str:
    value = str(profile or "balanced").strip().lower()

    if not value:
        value = "balanced"

    if value == "deep":
        raise DeltaAegisError("NetSniper scan profile 'deep' is planned but not runtime-enabled. Use quick, balanced, or accurate.")

    if value not in ALLOWED_NETSNIPER_SCAN_PROFILES:
        allowed = ", ".join(sorted(ALLOWED_NETSNIPER_SCAN_PROFILES))
        raise DeltaAegisError(f"invalid NetSniper scan profile: {profile!r}; allowed profiles: {allowed}")

    return value


def build_netsniper_headless_command(netsniper_path: Path, target: str, scan_profile: str = "balanced") -> list[str]:
    safe_target = validate_private_cidr(target)
    safe_profile = validate_netsniper_scan_profile(scan_profile)

    return [
        str(netsniper_path),
        "--non-interactive",
        "--target",
        safe_target,
        "--greenbone",
        "no",
        "--json-status",
        "--profile",
        safe_profile,
    ]



def create_scan_job(
    connection: sqlite3.Connection,
    target: str,
    netsniper_path: Path,
    runs_dir: Path,
    auto_ingest: bool = False,
    scan_profile: str = "balanced",
    schedule_id: str | None = None,
) -> dict[str, Any]:
    safe_target = validate_private_cidr(target)
    safe_profile = validate_netsniper_scan_profile(scan_profile)
    safe_schedule_id = str(schedule_id or "").strip()

    if len(safe_schedule_id) > 96:
        raise DeltaAegisError("scan schedule id is too long")

    now = utc_now_text()
    job_id = f"scan-{datetime.now(timezone.utc).strftime('%Y%m%d-%H%M%S')}-{uuid.uuid4().hex[:8]}"

    connection.execute(
        """
        INSERT INTO scan_jobs (
            job_id,
            target,
            network_scope,
            schedule_id,
            status,
            created_at,
            updated_at,
            netsniper_path,
            runs_dir,
            scan_profile,
            auto_ingest,
            status_json,
            message
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            job_id,
            safe_target,
            safe_target,
            safe_schedule_id,
            "QUEUED",
            now,
            now,
            str(netsniper_path),
            str(runs_dir),
            safe_profile,
            1 if auto_ingest else 0,
            "{}",
            "scan job queued",
        ),
    )

    return {
        "job_id": job_id,
        "target": safe_target,
        "network_scope": safe_target,
        "schedule_id": safe_schedule_id,
        "status": "QUEUED",
        "created_at": now,
        "updated_at": now,
        "heartbeat_at": None,
        "cancel_requested_at": None,
        "cancel_requested_by": "",
        "cancel_reason": "",
        "cancelled_at": None,
        "process_pid": None,
        "netsniper_path": str(netsniper_path),
        "runs_dir": str(runs_dir),
        "scan_profile": safe_profile,
        "auto_ingest": auto_ingest,
        "status_json": {},
        "message": "scan job queued",
    }

def update_scan_job(
    connection: sqlite3.Connection,
    job_id: str,
    **fields: Any,
) -> None:
    allowed = {
        "status",
        "started_at",
        "heartbeat_at",
        "cancel_requested_at",
        "cancel_requested_by",
        "cancel_reason",
        "cancelled_at",
        "finished_at",
        "process_pid",
        "bundle_path",
        "exit_code",
        "stdout_log",
        "stderr_log",
        "status_json",
        "message",
    }

    updates = []
    params: list[Any] = []

    for key, value in fields.items():
        if key not in allowed:
            raise DeltaAegisError(f"invalid scan job field update: {key}")

        if key == "status":
            value = str(value).upper()

            if value not in SCAN_JOB_STATUSES:
                raise DeltaAegisError(f"invalid scan job status: {value}")

        if key == "status_json":
            value = json.dumps(value or {}, sort_keys=True)

        updates.append(f"{key} = ?")
        params.append(value)

    updates.append("updated_at = ?")
    params.append(utc_now_text())
    params.append(job_id)

    connection.execute(
        f"""
        UPDATE scan_jobs
        SET {", ".join(updates)}
        WHERE job_id = ?
        """,
        tuple(params),
    )


def extract_netsniper_status_json(stdout_text: str) -> dict[str, Any]:
    text = stdout_text or ""
    decoder = json.JSONDecoder()
    best: dict[str, Any] | None = None

    index = text.find("{")

    while index != -1:
        try:
            value, _ = decoder.raw_decode(text[index:])
        except json.JSONDecodeError:
            index = text.find("{", index + 1)
            continue

        if isinstance(value, dict):
            best = value

            if any(
                key in value
                for key in (
                    "bundle_path",
                    "manifest_path",
                    "run_dir",
                    "run_directory",
                    "return_code",
                    "status",
                )
            ):
                best = value

        index = text.find("{", index + 1)

    return best or {}

def extract_netsniper_bundle_path(status_json: dict[str, Any]) -> str | None:
    for key in ("bundle_path", "bundle_dir", "run_dir", "run_directory"):
        value = status_json.get(key)

        if value:
            return str(value)

    return None


def netsniper_manifest_runtime_profile(manifest: dict[str, Any]) -> str:
    for key in (
        "scan_profile_effective",
        "scan_profile_requested",
        "effective_scan_profile",
        "requested_scan_profile",
        "profile",
    ):
        value = manifest.get(key)

        if value:
            return str(value).strip().lower()

    return ""


def netsniper_manifest_is_complete(manifest: dict[str, Any]) -> bool:
    return str(
        manifest.get("status")
        or manifest.get("run_status")
        or ""
    ).strip().upper() in {"COMPLETE", "COMPLETED"}


def netsniper_manifest_matches_scan_job(
    manifest: dict[str, Any],
    target: str,
    scan_profile: str,
) -> bool:
    manifest_target = str(
        manifest.get("target")
        or manifest.get("network_scope")
        or ""
    ).strip()

    if manifest_target != target:
        return False

    if not netsniper_manifest_is_complete(manifest):
        return False

    runtime_profile = netsniper_manifest_runtime_profile(manifest)

    if runtime_profile in ALLOWED_NETSNIPER_SCAN_PROFILES:
        return runtime_profile == scan_profile

    return True


def utc_text_to_epoch(value: str) -> float:
    try:
        parsed = datetime.fromisoformat(str(value).replace("Z", "+00:00"))
    except ValueError:
        return 0.0

    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)

    return parsed.timestamp()


def find_completed_netsniper_manifest_for_scan(
    runs_dir: Path,
    target: str,
    scan_profile: str,
    started_at: str,
) -> Path | None:
    runs_dir = Path(runs_dir).expanduser()
    threshold = max(0.0, utc_text_to_epoch(started_at) - 300.0)
    candidates: list[tuple[float, Path]] = []

    if not runs_dir.is_dir():
        return None

    for manifest_path in runs_dir.glob("*/manifest.json"):
        try:
            modified_at = manifest_path.stat().st_mtime
        except OSError:
            continue

        if modified_at < threshold:
            continue

        manifest = load_json_file(manifest_path, {})

        if not isinstance(manifest, dict):
            continue

        if not netsniper_manifest_matches_scan_job(manifest, target, scan_profile):
            continue

        candidates.append((modified_at, manifest_path))

    if not candidates:
        return None

    candidates.sort(reverse=True, key=lambda item: item[0])
    return candidates[0][1]


def enrich_netsniper_status_from_manifest(
    status_json: dict[str, Any],
    manifest_path: Path,
) -> dict[str, Any]:
    manifest = load_json_file(manifest_path, {})
    enriched = dict(status_json or {})

    enriched.setdefault("status", manifest.get("status") or "COMPLETE")
    enriched.setdefault("target", manifest.get("target"))
    enriched.setdefault("return_code", 0)
    enriched["run_dir"] = str(manifest_path.parent)
    enriched["manifest_path"] = str(manifest_path)

    if manifest.get("scan_id"):
        enriched.setdefault("scan_id", manifest.get("scan_id"))

    if manifest.get("scan_profile_effective"):
        enriched.setdefault("scan_profile_effective", manifest.get("scan_profile_effective"))

    if manifest.get("scan_profile_requested"):
        enriched.setdefault("scan_profile_requested", manifest.get("scan_profile_requested"))

    return enriched



def scan_job_auto_ingest_evidence(
    connection: sqlite3.Connection,
    manifest_path: Path | str,
    ingest_result: Any,
    status_json: dict[str, Any] | None = None,
) -> dict[str, Any]:
    """Build durable evidence that a scan bundle was ingested and quality-gated."""

    safe_manifest_path = Path(manifest_path).expanduser()
    status_payload = status_json if isinstance(status_json, dict) else {}
    scan_id = str(status_payload.get("scan_id") or "").strip()

    if not scan_id and safe_manifest_path.is_file():
        try:
            manifest_payload = json.loads(
                safe_manifest_path.read_text(encoding="utf-8")
            )
        except (OSError, json.JSONDecodeError):
            manifest_payload = {}

        if isinstance(manifest_payload, dict):
            scan_id = str(manifest_payload.get("scan_id") or "").strip()

    row = None

    if scan_id:
        row = connection.execute(
            """
            SELECT scan_id, quality_status, manifest_path, network_scope
            FROM snapshots
            WHERE scan_id = ?
            LIMIT 1
            """,
            (scan_id,),
        ).fetchone()

    if row is None:
        row = connection.execute(
            """
            SELECT scan_id, quality_status, manifest_path, network_scope
            FROM snapshots
            WHERE manifest_path = ?
            ORDER BY imported_at DESC
            LIMIT 1
            """,
            (str(safe_manifest_path),),
        ).fetchone()

    evidence = {
        "schema_version": "deltaaegis-scan-auto-ingest-evidence-v1",
        "requested": True,
        "attempted": True,
        "performed": True,
        "accepted": False,
        "quality_status": None,
        "scan_id": scan_id,
        "manifest_path": str(safe_manifest_path),
        "network_scope": None,
        "result": str(ingest_result),
    }

    if row is None:
        return evidence

    row_item = dict(row)
    quality_status = str(row_item.get("quality_status") or "").strip().upper()

    evidence.update(
        {
            "accepted": quality_status == "ACCEPTED",
            "quality_status": quality_status or None,
            "scan_id": str(row_item.get("scan_id") or scan_id),
            "manifest_path": str(
                row_item.get("manifest_path") or safe_manifest_path
            ),
            "network_scope": str(row_item.get("network_scope") or "") or None,
        }
    )

    return evidence



SCAN_JOB_CANCEL_ACTOR_MAX_LENGTH = 96
SCAN_JOB_CANCEL_REASON_MAX_LENGTH = 500
SCAN_JOB_CANCEL_GRACE_SECONDS = 5.0


def normalize_scan_job_cancel_actor(value: Any = None) -> str:
    actor = str(value or "operator").strip() or "operator"
    if len(actor) > SCAN_JOB_CANCEL_ACTOR_MAX_LENGTH:
        raise DeltaAegisError(
            f"scan cancellation requester exceeds "
            f"{SCAN_JOB_CANCEL_ACTOR_MAX_LENGTH} characters"
        )
    return actor


def normalize_scan_job_cancel_reason(value: Any = None) -> str:
    reason = (
        str(value or "operator requested cancellation").strip()
        or "operator requested cancellation"
    )
    if len(reason) > SCAN_JOB_CANCEL_REASON_MAX_LENGTH:
        raise DeltaAegisError(
            f"scan cancellation reason exceeds "
            f"{SCAN_JOB_CANCEL_REASON_MAX_LENGTH} characters"
        )
    return reason


def scan_job_row(
    connection: sqlite3.Connection,
    job_id: str,
) -> sqlite3.Row | None:
    return connection.execute(
        "SELECT * FROM scan_jobs WHERE job_id = ?",
        (str(job_id or "").strip(),),
    ).fetchone()


def scan_job_cancellation_request(
    connection: sqlite3.Connection,
    job_id: str,
) -> dict[str, Any]:
    row = scan_job_row(connection, job_id)
    if row is None:
        return {"found": False, "requested": False, "job": None}

    job = scan_job_to_dict(row)
    return {
        "found": True,
        "requested": bool(job.get("cancel_requested_at")),
        "requested_at": job.get("cancel_requested_at"),
        "requested_by": job.get("cancel_requested_by") or "",
        "reason": job.get("cancel_reason") or "",
        "job": job,
    }


def terminate_scan_process_group(
    process: subprocess.Popen,
    grace_seconds: float = SCAN_JOB_CANCEL_GRACE_SECONDS,
) -> int | None:
    if process.poll() is not None:
        return process.returncode

    try:
        os.killpg(process.pid, signal.SIGTERM)
    except ProcessLookupError:
        return process.poll()

    try:
        process.wait(timeout=max(0.1, float(grace_seconds)))
    except subprocess.TimeoutExpired:
        try:
            os.killpg(process.pid, signal.SIGKILL)
        except ProcessLookupError:
            pass
        process.wait()

    return process.returncode


def request_scan_job_cancellation(
    connection: sqlite3.Connection,
    job_id: Any,
    requested_by: Any = None,
    reason: Any = None,
) -> dict[str, Any]:
    safe_job_id = str(job_id or "").strip()

    if (
        not safe_job_id
        or len(safe_job_id) > 160
        or re.fullmatch(r"[A-Za-z0-9._:-]+", safe_job_id) is None
    ):
        raise DeltaAegisError("invalid scan job id")

    actor = normalize_scan_job_cancel_actor(requested_by)
    cancel_reason = normalize_scan_job_cancel_reason(reason)
    row = scan_job_row(connection, safe_job_id)

    if row is None:
        raise DeltaAegisError(f"scan job not found: {safe_job_id}")

    job = scan_job_to_dict(row)
    status = str(job.get("status") or "").upper()

    if status == "CANCELLED":
        job["cancellation_action"] = "already_cancelled"
        return job

    if status in {"COMPLETED", "FAILED"}:
        raise DeltaAegisError(
            f"cannot cancel terminal scan job {safe_job_id} with status {status}"
        )

    if job.get("cancel_requested_at"):
        job["cancellation_action"] = "already_requested"
        return job

    now = utc_now_text()
    status_json = dict(job.get("status_json") or {})
    status_json["cancellation"] = {
        "requested_at": now,
        "requested_by": actor,
        "reason": cancel_reason,
        "state": "CANCELLED_BEFORE_START" if status == "QUEUED" else "REQUESTED",
    }

    fields: dict[str, Any] = {
        "cancel_requested_at": now,
        "cancel_requested_by": actor,
        "cancel_reason": cancel_reason,
        "status_json": status_json,
        "message": f"scan cancellation requested by {actor}: {cancel_reason}",
    }

    if status == "QUEUED":
        fields.update(
            {
                "status": "CANCELLED",
                "cancelled_at": now,
                "finished_at": now,
                "heartbeat_at": now,
                "exit_code": 130,
                "message": (
                    f"scan cancelled before process launch by "
                    f"{actor}: {cancel_reason}"
                ),
            }
        )

    update_scan_job(connection, safe_job_id, **fields)
    updated_row = scan_job_row(connection, safe_job_id)

    if updated_row is None:
        raise DeltaAegisError(f"scan job disappeared unexpectedly: {safe_job_id}")

    result = scan_job_to_dict(updated_row)
    result["cancellation_action"] = (
        "cancelled_before_start" if status == "QUEUED" else "requested"
    )
    return result


def execute_scan_job(
    connection: sqlite3.Connection,
    job_id: str,
    target: str,
    netsniper_path: Path,
    runs_dir: Path,
    logs_dir: Path,
    events_path: Path,
    auto_ingest: bool = False,
    scan_profile: str = "balanced",
) -> dict[str, Any]:
    safe_target = validate_private_cidr(target)
    safe_profile = validate_netsniper_scan_profile(scan_profile)
    netsniper_path = Path(netsniper_path).expanduser()
    runs_dir = Path(runs_dir).expanduser()
    logs_dir = Path(logs_dir).expanduser()
    events_path = Path(events_path).expanduser()

    if not netsniper_path.is_file():
        raise DeltaAegisError(f"NetSniper executable not found: {netsniper_path}")

    command = build_netsniper_headless_command(netsniper_path, safe_target, safe_profile)

    logs_dir.mkdir(parents=True, exist_ok=True)

    stdout_log = logs_dir / f"{job_id}.stdout.log"
    stderr_log = logs_dir / f"{job_id}.stderr.log"

    started_at = utc_now_text()
    process = None
    cancellation_observed = False

    initial_cancellation = scan_job_cancellation_request(
        connection,
        job_id,
    )

    if (
        initial_cancellation.get("requested")
        or str(
            (initial_cancellation.get("job") or {}).get("status")
            or ""
        ).upper() == "CANCELLED"
    ):
        return initial_cancellation["job"]

    try:
        with (
            stdout_log.open("w", encoding="utf-8") as stdout_handle,
            stderr_log.open("w", encoding="utf-8") as stderr_handle,
        ):
            process = subprocess.Popen(
                command,
                cwd=str(netsniper_path.parent),
                text=True,
                stdout=stdout_handle,
                stderr=stderr_handle,
                start_new_session=True,
            )

            heartbeat_at = utc_now_text()

            start_cursor = connection.execute(
                "UPDATE scan_jobs "
                "SET status = ?, started_at = ?, heartbeat_at = ?, "
                "process_pid = ?, stdout_log = ?, stderr_log = ?, "
                "message = ?, updated_at = ? "
                "WHERE job_id = ? "
                "AND status = 'QUEUED' "
                "AND cancel_requested_at IS NULL",
                (
                    "RUNNING",
                    started_at,
                    heartbeat_at,
                    process.pid,
                    str(stdout_log),
                    str(stderr_log),
                    f"NetSniper scan running profile={safe_profile}",
                    heartbeat_at,
                    job_id,
                ),
            )
            connection.commit()

            if start_cursor.rowcount != 1:
                terminate_scan_process_group(process)
                blocked_row = scan_job_row(connection, job_id)

                if blocked_row is not None:
                    blocked_job = scan_job_to_dict(blocked_row)
                    if (
                        blocked_job.get("cancel_requested_at")
                        or blocked_job.get("status") == "CANCELLED"
                    ):
                        return blocked_job

                raise DeltaAegisError(
                    f"scan job could not transition from QUEUED "
                    f"to RUNNING: {job_id}"
                )

            while True:
                try:
                    return_code = process.wait(timeout=5.0)
                    final_request = scan_job_cancellation_request(
                        connection,
                        job_id,
                    )
                    cancellation_observed = bool(
                        final_request.get("requested")
                    )
                    break
                except subprocess.TimeoutExpired:
                    cancellation = scan_job_cancellation_request(
                        connection,
                        job_id,
                    )

                    if cancellation.get("requested"):
                        cancellation_observed = True
                        terminate_scan_process_group(process)
                        return_code = (
                            process.returncode
                            if process.returncode is not None
                            else 130
                        )
                        break

                    update_scan_job(
                        connection,
                        job_id,
                        heartbeat_at=utc_now_text(),
                    )
                    connection.commit()

    except KeyboardInterrupt as exc:
        if process is not None and process.poll() is None:
            try:
                os.killpg(process.pid, signal.SIGTERM)
                process.wait(timeout=5.0)
            except ProcessLookupError:
                pass
            except subprocess.TimeoutExpired:
                try:
                    os.killpg(process.pid, signal.SIGKILL)
                except ProcessLookupError:
                    pass
                process.wait()

        finished_at = utc_now_text()

        update_scan_job(
            connection,
            job_id,
            status="CANCELLED",
            heartbeat_at=finished_at,
            cancel_requested_at=finished_at,
            cancel_requested_by="cli",
            cancel_reason="keyboard interrupt",
            cancelled_at=finished_at,
            finished_at=finished_at,
            process_pid=process.pid if process is not None else None,
            stdout_log=str(stdout_log),
            stderr_log=str(stderr_log),
            exit_code=130,
            status_json={
                "cancellation": {
                    "requested_at": finished_at,
                    "requested_by": "cli",
                    "reason": "keyboard interrupt",
                    "state": "CANCELLED",
                }
            },
            message=f"NetSniper scan cancelled by CLI operator profile={safe_profile}",
        )
        connection.commit()

        raise DeltaAegisError(
            "NetSniper scan interrupted by operator"
        ) from exc

    except OSError as exc:
        if process is not None and process.poll() is None:
            try:
                os.killpg(process.pid, signal.SIGTERM)
                process.wait(timeout=5.0)
            except ProcessLookupError:
                pass
            except subprocess.TimeoutExpired:
                try:
                    os.killpg(process.pid, signal.SIGKILL)
                except ProcessLookupError:
                    pass
                process.wait()

        finished_at = utc_now_text()

        update_scan_job(
            connection,
            job_id,
            status="FAILED",
            started_at=started_at,
            heartbeat_at=finished_at,
            finished_at=finished_at,
            process_pid=process.pid if process is not None else None,
            stdout_log=str(stdout_log),
            stderr_log=str(stderr_log),
            exit_code=127,
            message=f"failed to launch NetSniper: {exc}",
        )
        connection.commit()

        raise DeltaAegisError(
            f"failed to launch NetSniper: {exc}"
        ) from exc

    cancellation = scan_job_cancellation_request(
        connection,
        job_id,
    )

    if cancellation_observed or cancellation.get("requested"):
        finished_at = utc_now_text()
        cancel_job = cancellation.get("job") or {}
        requested_at = cancel_job.get("cancel_requested_at") or finished_at
        requested_by = cancel_job.get("cancel_requested_by") or "operator"
        cancel_reason = (
            cancel_job.get("cancel_reason")
            or "operator requested cancellation"
        )
        status_json = dict(cancel_job.get("status_json") or {})
        cancellation_evidence = dict(status_json.get("cancellation") or {})
        cancellation_evidence.update(
            {
                "requested_at": requested_at,
                "requested_by": requested_by,
                "reason": cancel_reason,
                "cancelled_at": finished_at,
                "state": "CANCELLED",
                "process_return_code": return_code,
            }
        )
        status_json["cancellation"] = cancellation_evidence

        update_scan_job(
            connection,
            job_id,
            status="CANCELLED",
            heartbeat_at=finished_at,
            cancel_requested_at=requested_at,
            cancel_requested_by=requested_by,
            cancel_reason=cancel_reason,
            cancelled_at=finished_at,
            finished_at=finished_at,
            process_pid=process.pid if process is not None else None,
            stdout_log=str(stdout_log),
            stderr_log=str(stderr_log),
            exit_code=130,
            status_json=status_json,
            message=(
                f"NetSniper scan cancelled by {requested_by}: "
                f"{cancel_reason}; process_return_code={return_code}"
            ),
        )
        connection.commit()

        cancelled_row = scan_job_row(connection, job_id)
        if cancelled_row is None:
            raise DeltaAegisError(
                f"scan job disappeared unexpectedly: {job_id}"
            )
        return scan_job_to_dict(cancelled_row)

    stdout_text = stdout_log.read_text(
        encoding="utf-8",
        errors="replace",
    )

    status_json = extract_netsniper_status_json(stdout_text)

    if not isinstance(status_json, dict):
        status_json = {}

    bundle_path = extract_netsniper_bundle_path(status_json)

    if return_code == 0 and not bundle_path:
        manifest_path = find_completed_netsniper_manifest_for_scan(
            runs_dir,
            safe_target,
            safe_profile,
            started_at,
        )

        if manifest_path is not None:
            status_json = enrich_netsniper_status_from_manifest(status_json, manifest_path)
            bundle_path = str(manifest_path.parent)

    final_status = "COMPLETED" if return_code == 0 else "FAILED"

    message_parts = []

    if final_status == "COMPLETED":
        message_parts.append(f"NetSniper scan completed profile={safe_profile}")
    else:
        message_parts.append(f"NetSniper scan failed with exit code {return_code} profile={safe_profile}")

    if bundle_path:
        message_parts.append(f"bundle={bundle_path}")

    auto_ingest_evidence = {
        "schema_version": "deltaaegis-scan-auto-ingest-evidence-v1",
        "requested": bool(auto_ingest),
        "attempted": False,
        "performed": False,
        "accepted": False,
        "quality_status": None,
        "scan_id": str(status_json.get("scan_id") or ""),
        "manifest_path": None,
        "network_scope": None,
        "result": None,
    }

    if final_status == "COMPLETED" and auto_ingest:
        auto_ingest_evidence["attempted"] = True

        if not bundle_path:
            final_status = "FAILED"
            message_parts.append("auto-ingest failed: completed scan did not provide a bundle path")
        else:
            manifest = Path(bundle_path) / "manifest.json"
            auto_ingest_evidence["manifest_path"] = str(manifest)

            if manifest.is_file():
                ingest_result = ingest_manifest(connection, manifest, events_path)
                auto_ingest_evidence = scan_job_auto_ingest_evidence(
                    connection, manifest, ingest_result, status_json=status_json
                )
                message_parts.append(f"auto-ingest={ingest_result}")
                message_parts.append(
                    "auto-ingest-quality="
                    f"{auto_ingest_evidence.get('quality_status') or 'UNKNOWN'}"
                )
            else:
                final_status = "FAILED"
                message_parts.append(f"auto-ingest failed: manifest not found at {manifest}")

    status_json["auto_ingest"] = auto_ingest_evidence

    finished_at = utc_now_text()

    update_scan_job(
        connection,
        job_id,
        status=final_status,
        heartbeat_at=finished_at,
        finished_at=finished_at,
        bundle_path=bundle_path,
        exit_code=return_code,
        status_json=status_json,
        message="; ".join(message_parts),
    )

    connection.commit()

    row = connection.execute(
        "SELECT * FROM scan_jobs WHERE job_id = ?",
        (job_id,),
    ).fetchone()

    if row is None:
        raise DeltaAegisError(f"scan job disappeared unexpectedly: {job_id}")

    return scan_job_to_dict(row)


def command_scan_start(args: argparse.Namespace) -> int:
    connection = connect(args.db)

    safe_target = validate_private_cidr(args.target)
    safe_profile = validate_netsniper_scan_profile(args.profile)
    netsniper_path = Path(args.netsniper_path).expanduser()
    logs_dir = Path(args.scan_logs_dir).expanduser()
    runs_dir = Path(args.runs_dir).expanduser()

    job = create_scan_job(
        connection,
        safe_target,
        netsniper_path,
        runs_dir,
        auto_ingest=args.auto_ingest,
        scan_profile=safe_profile,
    )
    connection.commit()

    print(f"Created scan job: {job['job_id']}")
    print(f"Target: {safe_target}")
    print(f"NetSniper: {netsniper_path}")
    print(f"Scan profile: {safe_profile}")
    print(f"Auto-ingest: {'yes' if args.auto_ingest else 'no'}")
    print()

    try:
        result = execute_scan_job(
            connection,
            job["job_id"],
            safe_target,
            netsniper_path,
            runs_dir,
            logs_dir,
            args.events,
            auto_ingest=args.auto_ingest,
            scan_profile=safe_profile,
        )
    except DeltaAegisError as exc:
        print(f"Scan job failed: {exc}", file=sys.stderr)
        return 1

    print(f"Job: {result['job_id']}")
    print(f"Status: {result['status']}")
    print(f"Exit code: {result.get('exit_code')}")
    print(f"Stdout log: {result.get('stdout_log') or '-'}")
    print(f"Stderr log: {result.get('stderr_log') or '-'}")

    if result.get("bundle_path"):
        print(f"Bundle: {result['bundle_path']}")

    if result.get("message"):
        print(f"Message: {result['message']}")

    return 0 if result["status"] == "COMPLETED" else 1


def decode_json_field(value: str | None, default):
    if not value:
        return default

    try:
        return json.loads(value)
    except (TypeError, json.JSONDecodeError):
        return default


def scan_job_to_dict(row: sqlite3.Row | dict[str, Any]) -> dict[str, Any]:
    item = dict(row)

    item["auto_ingest"] = bool(item.get("auto_ingest"))
    item["scan_profile"] = item.get("scan_profile") or "balanced"
    item["schedule_id"] = item.get("schedule_id") or ""

    process_pid = item.get("process_pid")
    if process_pid in ("", None):
        item["process_pid"] = None
    else:
        try:
            item["process_pid"] = int(process_pid)
        except (TypeError, ValueError):
            item["process_pid"] = None

    item["heartbeat_at"] = item.get("heartbeat_at") or None
    item["cancel_requested_at"] = item.get("cancel_requested_at") or None
    item["cancel_requested_by"] = item.get("cancel_requested_by") or ""
    item["cancel_reason"] = item.get("cancel_reason") or ""
    item["cancelled_at"] = item.get("cancelled_at") or None
    item["status_json"] = decode_json_field(item.get("status_json"), {})

    return item


def query_scan_jobs(
    connection: sqlite3.Connection,
    limit: int = 20,
    status: str | None = None,
    scope: str | None = None,
) -> list[sqlite3.Row]:
    clauses = []
    params: list[Any] = []

    if status:
        normalized_status = status.strip().upper()

        if normalized_status not in SCAN_JOB_STATUSES:
            raise DeltaAegisError(f"invalid scan job status: {status}")

        clauses.append("status = ?")
        params.append(normalized_status)

    if scope:
        clauses.append("network_scope = ?")
        params.append(scope)

    where = " WHERE " + " AND ".join(clauses) if clauses else ""

    params.append(limit)

    return connection.execute(
        f"""
        SELECT
            job_id,
            target,
            network_scope,
            schedule_id,
            status,
            created_at,
            updated_at,
            started_at,
            heartbeat_at,
            cancel_requested_at,
            cancel_requested_by,
            cancel_reason,
            cancelled_at,
            finished_at,
            process_pid,
            netsniper_path,
            runs_dir,
            scan_profile,
            bundle_path,
            exit_code,
            auto_ingest,
            stdout_log,
            stderr_log,
            status_json,
            message
        FROM scan_jobs
        {where}
        ORDER BY created_at DESC, updated_at DESC
        LIMIT ?
        """,
        tuple(params),
    ).fetchall()


def dashboard_scan_jobs_payload(
    connection: sqlite3.Connection,
    limit: int = 20,
    scope: str | None = None,
    status: str | None = None,
) -> list[dict[str, Any]]:
    jobs: list[dict[str, Any]] = []

    for row in query_scan_jobs(
        connection,
        limit=limit,
        status=status,
        scope=scope,
    ):
        job = scan_job_to_dict(row)

        if str(job.get("status") or "").upper() in {"QUEUED", "RUNNING"}:
            job["watchdog"] = scan_job_watchdog_evaluation(job)

        jobs.append(job)

    return jobs




SCAN_JOB_LOG_TAIL_DEFAULT_BYTES = 16 * 1024
SCAN_JOB_LOG_TAIL_MINIMUM_BYTES = 1024
SCAN_JOB_LOG_TAIL_MAXIMUM_BYTES = 64 * 1024


def normalize_scan_job_log_tail_bytes(value: Any = None) -> int:
    try:
        requested = int(value or SCAN_JOB_LOG_TAIL_DEFAULT_BYTES)
    except (TypeError, ValueError):
        requested = SCAN_JOB_LOG_TAIL_DEFAULT_BYTES

    return max(
        SCAN_JOB_LOG_TAIL_MINIMUM_BYTES,
        min(SCAN_JOB_LOG_TAIL_MAXIMUM_BYTES, requested),
    )


def scan_job_log_tail_payload(
    path_value: Any,
    job_id: str,
    stream: str,
    logs_root: Path,
    max_bytes: Any = None,
) -> dict[str, Any]:
    safe_stream = str(stream or "").strip().lower()

    if safe_stream not in {"stdout", "stderr"}:
        raise DeltaAegisError(
            f"unsupported scan job log stream: {stream!r}"
        )

    limit = normalize_scan_job_log_tail_bytes(max_bytes)
    payload = {
        "stream": safe_stream,
        "available": False,
        "text": "",
        "truncated": False,
        "file_size": 0,
        "bytes_read": 0,
        "tail_bytes_limit": limit,
        "updated_at": None,
        "reason": None,
    }

    if not path_value:
        payload["reason"] = "log_path_not_recorded"
        return payload

    root = Path(logs_root).expanduser().resolve()
    candidate = Path(str(path_value)).expanduser().resolve()
    expected_name = f"{job_id}.{safe_stream}.log"

    try:
        candidate.relative_to(root)
    except ValueError:
        payload["reason"] = "log_path_outside_allowed_root"
        return payload

    if candidate.name != expected_name:
        payload["reason"] = "unexpected_log_filename"
        return payload

    if not candidate.is_file():
        payload["reason"] = "log_file_not_found"
        return payload

    try:
        stat = candidate.stat()
        file_size = int(stat.st_size)
        start = max(0, file_size - limit)

        with candidate.open("rb") as handle:
            handle.seek(start)
            content = handle.read(limit)

        payload.update(
            {
                "available": True,
                "text": content.decode(
                    "utf-8",
                    errors="replace",
                ),
                "truncated": start > 0,
                "file_size": file_size,
                "bytes_read": len(content),
                "updated_at": datetime.fromtimestamp(
                    stat.st_mtime,
                    timezone.utc,
                ).isoformat(timespec="seconds"),
            }
        )
    except OSError as exc:
        payload["reason"] = f"log_read_failed:{exc.__class__.__name__}"

    return payload



def dashboard_netsniper_scan_cancel_payload(
    connection: sqlite3.Connection,
    payload: dict[str, Any],
    actor: dict[str, Any] | None = None,
    source_ip: str | None = None,
    user_agent: str | None = None,
) -> dict[str, Any]:
    if not isinstance(payload, dict):
        raise DashboardAdminUserActionError(
            "scan cancellation payload must be a JSON object",
            status_code=400,
        )

    job_id = str(payload.get("job_id") or "").strip()
    reason = payload.get("reason")

    if (
        not job_id
        or len(job_id) > 160
        or re.fullmatch(r"[A-Za-z0-9._:-]+", job_id) is None
    ):
        raise DashboardAdminUserActionError(
            "invalid scan job id",
            status_code=400,
        )

    existing_row = scan_job_row(connection, job_id)

    if existing_row is None:
        raise DashboardAdminUserActionError(
            f"scan job not found: {job_id}",
            status_code=404,
        )

    actor_summary = dashboard_actor_summary(actor)
    requested_by = actor_summary.get("username") or "dashboard.admin"

    job = request_scan_job_cancellation(
        connection,
        job_id,
        requested_by=requested_by,
        reason=reason,
    )

    cancellation_action = str(
        job.get("cancellation_action") or "requested"
    )

    record_access_audit_event(
        connection,
        action="NETSNIPER_SCAN_CANCEL_REQUEST",
        actor=actor or actor_summary,
        target_type="scan_job",
        target_key=job_id,
        source_ip=source_ip,
        user_agent=user_agent,
        details={
            "job_id": job_id,
            "status": job.get("status"),
            "cancellation_action": cancellation_action,
            "requested_by": job.get("cancel_requested_by"),
            "reason": job.get("cancel_reason"),
            "cancel_requested_at": job.get("cancel_requested_at"),
            "cancelled_at": job.get("cancelled_at"),
        },
    )

    message = (
        "Scan cancellation request accepted."
        if cancellation_action == "requested"
        else "Scan cancellation state recorded."
    )
    receipt = dashboard_action_receipt(
        "netsniper.scan_cancel",
        message,
        severity="warning",
        summary={
            "status": job.get("status") or "",
            "cancellation_action": cancellation_action,
            "requested_by": (
                job.get("cancel_requested_by")
                or requested_by
            ),
        },
        identifiers={
            "job_id": job_id,
        },
        diagnostic_detail={
            "available": bool(
                job.get("cancel_reason")
                or job.get("cancel_requested_at")
                or job.get("cancelled_at")
            ),
            "reason": job.get("cancel_reason") or "",
            "cancel_requested_at": (
                job.get("cancel_requested_at")
                or ""
            ),
            "cancelled_at": job.get("cancelled_at") or "",
        },
    )

    return {
        "ok": True,
        "action": "netsniper.scan.cancel",
        "job_id": job_id,
        "cancellation_action": cancellation_action,
        "job": job,
        "message": message,
        "receipt": receipt,
    }

def dashboard_scan_job_detail_payload(
    connection: sqlite3.Connection,
    job_id: Any,
    tail_bytes: Any = None,
    logs_root: Path | None = None,
) -> dict[str, Any]:
    safe_job_id = str(job_id or "").strip()

    if (
        not safe_job_id
        or len(safe_job_id) > 160
        or re.fullmatch(r"[A-Za-z0-9._:-]+", safe_job_id) is None
    ):
        return {
            "ok": False,
            "found": False,
            "job_id": safe_job_id,
            "error": "invalid scan job id",
        }

    row = connection.execute(
        "SELECT * FROM scan_jobs WHERE job_id = ?",
        (safe_job_id,),
    ).fetchone()

    if row is None:
        return {
            "ok": False,
            "found": False,
            "job_id": safe_job_id,
            "error": "scan job not found",
        }

    job = scan_job_to_dict(row)
    job["watchdog"] = scan_job_watchdog_evaluation(job)
    safe_logs_root = Path(
        logs_root if logs_root is not None else DEFAULT_SCAN_LOGS
    ).expanduser()

    return {
        "ok": True,
        "found": True,
        "job_id": safe_job_id,
        "tail_bytes": normalize_scan_job_log_tail_bytes(tail_bytes),
        "job": job,
        "stdout": scan_job_log_tail_payload(
            job.get("stdout_log"),
            safe_job_id,
            "stdout",
            safe_logs_root,
            tail_bytes,
        ),
        "stderr": scan_job_log_tail_payload(
            job.get("stderr_log"),
            safe_job_id,
            "stderr",
            safe_logs_root,
            tail_bytes,
        ),
    }


def trueaegis_job_to_dict(row: sqlite3.Row | dict[str, Any]) -> dict[str, Any]:
    item = dict(row)

    for key in ("imported_observations", "correlation_count"):
        try:
            item[key] = int(item.get(key) or 0)
        except (TypeError, ValueError):
            item[key] = 0

    if item.get("exit_code") in ("", None):
        item["exit_code"] = None
    else:
        try:
            item["exit_code"] = int(item.get("exit_code"))
        except (TypeError, ValueError):
            item["exit_code"] = None

    item["scan_job_id"] = str(item.get("scan_job_id") or "")
    item["schedule_id"] = str(item.get("schedule_id") or "")
    item["trigger_source"] = str(item.get("trigger_source") or "manual_dashboard")

    return item


def create_trueaegis_job(
    connection: sqlite3.Connection,
    scan_id: str | None,
    network_scope: str | None,
    manifest_path: Path,
    trueaegis_path: Path,
    scan_job_id: str | None = None,
    schedule_id: str | None = None,
    trigger_source: str = "manual_dashboard",
) -> dict[str, Any]:
    safe_manifest_path = Path(manifest_path).expanduser()
    safe_trueaegis_path = Path(trueaegis_path).expanduser()
    safe_scan_job_id = str(scan_job_id or "").strip()
    safe_schedule_id = str(schedule_id or "").strip()
    safe_trigger_source = str(trigger_source or "manual_dashboard").strip().lower()

    if safe_trigger_source not in {"manual_dashboard", "scheduled_followup"}:
        raise DeltaAegisError(f"invalid TrueAegis trigger source: {trigger_source}")

    now = utc_now_text()
    job_id = f"trueaegis-{datetime.now(timezone.utc).strftime('%Y%m%d-%H%M%S')}-{uuid.uuid4().hex[:8]}"

    connection.execute(
        """
        INSERT INTO trueaegis_jobs (
            job_id,
            status,
            scan_id,
            scan_job_id,
            schedule_id,
            trigger_source,
            network_scope,
            manifest_path,
            trueaegis_path,
            message,
            created_at,
            updated_at
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            job_id,
            "QUEUED",
            str(scan_id or ""),
            safe_scan_job_id,
            safe_schedule_id,
            safe_trigger_source,
            str(network_scope or ""),
            str(safe_manifest_path),
            str(safe_trueaegis_path),
            "TrueAegis validation job queued",
            now,
            now,
        ),
    )

    row = connection.execute(
        "SELECT * FROM trueaegis_jobs WHERE job_id = ?",
        (job_id,),
    ).fetchone()

    if row is None:
        raise DeltaAegisError(f"TrueAegis job was not created: {job_id}")

    return trueaegis_job_to_dict(row)


def update_trueaegis_job(
    connection: sqlite3.Connection,
    job_id: str,
    **fields: Any,
) -> None:
    allowed = {
        "status",
        "started_at",
        "completed_at",
        "validation_results_path",
        "validation_run_id",
        "imported_observations",
        "correlation_count",
        "stdout_log_path",
        "stderr_log_path",
        "exit_code",
        "message",
    }

    updates = []
    params: list[Any] = []

    for key, value in fields.items():
        if key not in allowed:
            raise DeltaAegisError(f"invalid TrueAegis job field update: {key}")

        if key == "status":
            value = str(value).upper()

            if value not in TRUEAEGIS_JOB_STATUSES:
                raise DeltaAegisError(f"invalid TrueAegis job status: {value}")

        if key in {"imported_observations", "correlation_count"}:
            value = max(0, int(value or 0))

        updates.append(f"{key} = ?")
        params.append(value)

    if not updates:
        return

    updates.append("updated_at = ?")
    params.append(utc_now_text())
    params.append(job_id)

    connection.execute(
        f"""
        UPDATE trueaegis_jobs
        SET {", ".join(updates)}
        WHERE job_id = ?
        """,
        tuple(params),
    )


def query_trueaegis_jobs(
    connection: sqlite3.Connection,
    limit: int = 20,
    status: str | None = None,
    scope: str | None = None,
) -> list[sqlite3.Row]:
    clauses = []
    params: list[Any] = []

    if status:
        normalized_status = status.strip().upper()

        if normalized_status not in TRUEAEGIS_JOB_STATUSES:
            raise DeltaAegisError(f"invalid TrueAegis job status: {status}")

        clauses.append("status = ?")
        params.append(normalized_status)

    if scope:
        clauses.append("network_scope = ?")
        params.append(scope)

    where = " WHERE " + " AND ".join(clauses) if clauses else ""

    try:
        safe_limit = int(limit)
    except (TypeError, ValueError):
        safe_limit = 20

    safe_limit = max(1, min(safe_limit, 200))
    params.append(safe_limit)

    return connection.execute(
        f"""
        SELECT
            job_id,
            status,
            scan_id,
            scan_job_id,
            schedule_id,
            trigger_source,
            network_scope,
            manifest_path,
            trueaegis_path,
            validation_results_path,
            validation_run_id,
            imported_observations,
            correlation_count,
            stdout_log_path,
            stderr_log_path,
            exit_code,
            message,
            created_at,
            updated_at,
            started_at,
            completed_at
        FROM trueaegis_jobs
        {where}
        ORDER BY created_at DESC, updated_at DESC
        LIMIT ?
        """,
        tuple(params),
    ).fetchall()


def dashboard_trueaegis_jobs_payload(
    connection: sqlite3.Connection,
    limit: int = 20,
    scope: str | None = None,
    status: str | None = None,
) -> list[dict[str, Any]]:
    return [
        trueaegis_job_to_dict(row)
        for row in query_trueaegis_jobs(
            connection,
            limit=limit,
            status=status,
            scope=scope,
        )
    ]



