    if not members:
        print("No network scopes are assigned to this logical site.")
        return

    print(
        f"{'Network scope':<20} "
        f"{'Observed':<9} "
        f"{'Snapshots':>9} "
        f"{'Accepted':>8} "
        f"Latest scan"
    )
