def command_alert_notes(args):
    connection = connect(args.db)

    alert = connection.execute(
        """
        SELECT alert_id, status, severity, event_type, subject_key, summary
        FROM alerts
        WHERE alert_id = ?
        """,
        (args.alert_id,),
    ).fetchone()

    if alert is None:
        print(f"No alert found with alert_id={args.alert_id}")
        return 1

    notes = connection.execute(
        """
        SELECT note_id, action, reason, created_at
        FROM alert_notes
        WHERE alert_id = ?
        ORDER BY note_id ASC
        """,
        (args.alert_id,),
    ).fetchall()

    print(f"Alert Notes: {args.alert_id}")
    print("=" * (13 + len(str(args.alert_id))))
    print()
    print(f"Status:   {alert['status']}")
    print(f"Severity: {alert['severity']}")
    print(f"Type:     {alert['event_type']}")
    print(f"Subject:  {alert['subject_key']}")
    print(f"Summary:  {alert['summary']}")
    print()

    if not notes:
        print("No review notes have been recorded for this alert.")
        return 0

    for note in notes:
        print(f"[{note['note_id']}] {note['created_at']}  {note['action']}")
        print(f"  Reason: {note['reason']}")
        print()

    return 0

def command_asset_timeline(args):
    connection = connect(args.db)

    clauses = ["(subject_key = ? OR subject_key LIKE ?)"]
    params = [args.asset_key, f"%{args.asset_key}%"]

    if args.severity:
        clauses.append("severity = ?")
        params.append(args.severity.upper())

    params.append(args.limit)

    rows = connection.execute(
        f"""
        SELECT
            event_id,
            scan_id,
            baseline_scan_id,
            created_at,
            severity,
            event_type,
            subject_key,
            previous_value,
            current_value,
            summary
        FROM delta_events
        WHERE {" AND ".join(clauses)}
        ORDER BY created_at ASC, event_id ASC
        LIMIT ?
        """,
        tuple(params),
    ).fetchall()

    print(f"Asset Timeline: {args.asset_key}")
    print("=" * (16 + len(args.asset_key)))
    print()

    if not rows:
        print("No delta events matched this asset or subject key.")
        return 0

    for row in rows:
        print(f"[{row['event_id']}] {row['created_at']}  {row['severity']}  {row['event_type']}")
        print(f"  Subject:  {row['subject_key']}")
        print(f"  Snapshot: {row['scan_id']}")
        print(f"  Baseline: {row['baseline_scan_id'] or '-'}")

        if row["previous_value"]:
            print(f"  Previous: {row['previous_value']}")

        if row["current_value"]:
            print(f"  Current:  {row['current_value']}")

        print(f"  Summary:  {row['summary']}")
        print()

    return 0


def command_alert_detail(args):
    connection = connect(args.db)

    alert = connection.execute(
        """
        SELECT *
        FROM alerts
        WHERE alert_id = ?
        """,
        (args.alert_id,),
    ).fetchone()

    if alert is None:
        print(f"No alert found with alert_id={args.alert_id}")
        return 1

    alert_columns = set(alert.keys())

    print(f"Alert Detail: {args.alert_id}")
    print("=" * (14 + len(str(args.alert_id))))
    print()

    for field in [
        "alert_id",
        "status",
        "severity",
        "event_type",
        "subject_key",
        "opened_at",
        "updated_at",
        "resolved_at",
        "suppressed_at",
        "summary",
    ]:
        if field in alert_columns:
            print(f"{field}: {alert[field]}")

    print()

    related_event = None

    if "event_id" in alert_columns and alert["event_id"] is not None:
        related_event = connection.execute(
            """
            SELECT *
            FROM delta_events
            WHERE event_id = ?
            """,
            (alert["event_id"],),
        ).fetchone()

    if related_event is None and {"event_type", "subject_key"}.issubset(alert_columns):
        related_event = connection.execute(
            """
            SELECT *
            FROM delta_events
            WHERE event_type = ?
              AND subject_key = ?
            ORDER BY event_id DESC
            LIMIT 1
            """,
            (alert["event_type"], alert["subject_key"]),
        ).fetchone()

    if related_event:
        print("Related Event")
        print("-------------")

        for field in [
            "event_id",
            "scan_id",
            "baseline_scan_id",
            "created_at",
            "severity",
            "event_type",
            "subject_key",
            "previous_value",
            "current_value",
            "summary",
        ]:
            if field in related_event.keys():
                print(f"{field}: {related_event[field]}")

        print()

        print("Why this matters")
        print("----------------")
        print(severity_explanation(related_event["severity"]))
        print()

        print("Recommended follow-up")
        print("---------------------")
        for item in recommended_followup(related_event["event_type"]):
            print(f"- {item}")

        print()
    else:
        print("No directly related delta event was found.")
        print()


    notes = connection.execute(
        """
        SELECT note_id, action, reason, created_at
        FROM alert_notes
        WHERE alert_id = ?
        ORDER BY note_id ASC
        """,
        (args.alert_id,),
    ).fetchall()

    print("Review Notes")
    print("------------")

    if not notes:
        print("No review notes have been recorded for this alert.")
    else:
        for note in notes:
            print(f"[{note['note_id']}] {note['created_at']}  {note['action']}")
            print(f"  Reason: {note['reason']}")

    print()

    return 0



def dashboard_json_response(handler, payload, status=200):
    body = json.dumps(payload, indent=2, default=str).encode("utf-8")

    handler.send_response(status)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    handler.send_header("Cache-Control", "no-store")
    handler.send_header("Content-Length", str(len(body)))
    handler.end_headers()
    try:
        handler.wfile.write(body)
    except (BrokenPipeError, ConnectionResetError):
        return





def dashboard_inject_operator_floating_button(html_text: str) -> str:
    # Do not inject dashboard-only polish into auth/operator pages.
    if (
        "<title>DeltaAegis Operator" in html_text
        or "<title>DeltaAegis Login" in html_text
        or "<title>DeltaAegis First Admin Setup" in html_text
    ):
        return html_text

    if not isinstance(html_text, str):
        return html_text

    if "</body>" not in html_text:
        return html_text

    # Do not inject dashboard-only polish into operator pages.
    if "DeltaAegis Operator Session" in html_text or "DeltaAegis User Management" in html_text:
        return html_text

    polish_style = """
<style id="deltaaegis-v026-dashboard-polish-style">
  a[href="/operator"]:not(#deltaaegis-operator-floating-button) {
    display: none !important;
  }
</style>
"""

    polish_script = """
<script id="deltaaegis-v026-dashboard-polish-script">
(function () {
  function replaceText(node, fromText, toText) {
    if (!node || !node.childNodes) { return; }

    for (const child of Array.from(node.childNodes)) {
      if (child.nodeType === Node.TEXT_NODE && child.nodeValue && child.nodeValue.includes(fromText)) {
        child.nodeValue = child.nodeValue.replaceAll(fromText, toText);
      } else {
        replaceText(child, fromText, toText);
      }
    }
  }

  function removeLegacyOperatorLinks() {
    document.querySelectorAll('a[href="/operator"]').forEach(function (link) {
      if (link.id !== "deltaaegis-operator-floating-button") {
        link.remove();
      }
    });
  }

  function hideDashboardAccessAuditTrail() {
    const headings = Array.from(document.querySelectorAll("h1,h2,h3,h4"));
    headings.forEach(function (heading) {
      if ((heading.textContent || "").trim() !== "Access Audit Trail") {
        return;
      }

      let node = heading;
      while (node) {
        const next = node.nextElementSibling;
        node.setAttribute("data-deltaaegis-v026-moved-audit", "true");
        node.style.display = "none";

        if (next && /^H[1-4]$/.test(next.tagName || "")) {
          break;
        }

        node = next;
      }
    });
  }

  function applyDashboardPolish() {
    replaceText(document.body, "v0.26 User Management", "v0.26 User Management");
    replaceText(document.body, "v0.26 user management", "v0.26 user management");
    removeLegacyOperatorLinks();
    hideDashboardAccessAuditTrail();
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", applyDashboardPolish);
  } else {
    applyDashboardPolish();
  }

  const observer = new MutationObserver(applyDashboardPolish);
  observer.observe(document.documentElement, { childList: true, subtree: true });
})();
</script>
"""

    floating_button = """
  <a
    id="deltaaegis-operator-floating-button"
    href="/operator"
    aria-label="Open operator session page"
    title="Open operator session page"
    style="
      position: fixed;
      right: 20px;
      bottom: 20px;
      z-index: 9999;
      border: 1px solid rgba(34, 211, 238, 0.38);
      border-radius: 999px;
      background: rgba(8, 145, 178, 0.92);
      color: #ecfeff;
      box-shadow: 0 18px 40px rgba(0, 0, 0, 0.35);
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
      font-size: 13px;
      font-weight: 950;
      padding: 11px 15px;
      text-decoration: none;
      backdrop-filter: blur(10px);
    "
  >Operator</a>
"""

    if 'id="deltaaegis-v026-dashboard-polish-style"' not in html_text and "</head>" in html_text:
        html_text = html_text.replace("</head>", polish_style + "\n</head>", 1)

    if 'id="deltaaegis-v026-dashboard-polish-script"' not in html_text:
        html_text = html_text.replace("</body>", polish_script + "\n</body>", 1)

    if 'id="deltaaegis-operator-floating-button"' not in html_text:
        html_text = html_text.replace("</body>", floating_button + "\n</body>", 1)

    return html_text



