def dashboard_safe_query(connection, sql, params=()):
    try:
        rows = connection.execute(sql, params).fetchall()
    except Exception:
        return []

    return [dict(row) for row in rows]


def dashboard_json_list(value):
    if value is None or value == "":
        return []

    try:
        decoded = json.loads(value)
    except (TypeError, json.JSONDecodeError):
        return []

    return decoded if isinstance(decoded, list) else []


def dashboard_enrich_classification_payload(row):
    if row is None:
        return None

    item = dict(row)

    evidence = dashboard_json_list(item.get("classification_evidence_json"))
    contradictions = dashboard_json_list(item.get("classification_contradictions_json"))
    candidates = dashboard_json_list(item.get("classification_candidates_json"))

    item["classification_evidence"] = evidence
    item["classification_contradictions"] = contradictions
    item["classification_candidates"] = candidates
    item["classification_evidence_count"] = len(evidence)
    item["classification_contradiction_count"] = len(contradictions)
    item["classification_candidate_count"] = len(candidates)

    item["classification_display_type"] = (
        item.get("classification_type")
        or item.get("classification_primary_type")
        or item.get("device_type")
        or "Unknown"
    )

    item["classification_display_decision"] = (
        item.get("classification_decision")
        or "unknown"
    )

    item["classification_display_confidence"] = (
        item.get("classification_confidence")
        if item.get("classification_confidence") is not None
        else item.get("device_type_confidence")
    )

    if item["classification_display_confidence"] is None:
        item["classification_display_confidence"] = 0

    item["classification_has_intelligence"] = bool(
        item.get("classification_type")
        or item.get("classification_primary_type")
        or item.get("classification_method")
        or item.get("classification_confidence") is not None
        or evidence
        or contradictions
        or candidates
    )

    return item


def dashboard_enrich_classification_rows(rows):
    return [dashboard_enrich_classification_payload(row) for row in rows]


def dashboard_int(value, default=0):
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def dashboard_classification_summary_payload(connection, scope=None, limit=10):
    assets = dashboard_assets_payload(
        connection,
        limit=10000,
        scope=scope,
    )

    total_assets = len(assets)
    classified_assets = 0
    possible_assets = 0
    unknown_assets = 0
    evidence_backed_assets = 0
    contradiction_assets = 0
    high_confidence_assets = 0

    type_counts = {}
    review_rows = []

    for asset in assets:
        decision = str(asset.get("classification_display_decision") or "unknown").lower()
        classification = str(asset.get("classification_display_type") or "Unknown").strip()
        confidence = dashboard_int(asset.get("classification_display_confidence"), 0)
        evidence_count = dashboard_int(asset.get("classification_evidence_count"), 0)
        contradiction_count = dashboard_int(asset.get("classification_contradiction_count"), 0)

        is_unknown_type = classification in {"", "Unknown", "Unknown / Ambiguous"}

        if decision == "classified":
            classified_assets += 1
        elif decision == "possible":
            possible_assets += 1
        else:
            unknown_assets += 1

        if evidence_count > 0:
            evidence_backed_assets += 1

        if contradiction_count > 0:
            contradiction_assets += 1

        if confidence >= 80:
            high_confidence_assets += 1

        if not is_unknown_type:
            type_counts[classification] = type_counts.get(classification, 0) + 1

        review_reason = None
        review_priority = 99

        if contradiction_count > 0:
            review_reason = "Classification contradiction present"
            review_priority = 1
        elif decision == "possible":
            review_reason = "Weak/possible classification"
            review_priority = 2
        elif decision == "unknown" or confidence == 0 or is_unknown_type:
            review_reason = "Unknown or ambiguous classification"
            review_priority = 3
        elif confidence < 40:
            review_reason = "Low classification confidence"
            review_priority = 4

        if review_reason:
            review_rows.append(
                {
                    "asset_key": asset.get("asset_key"),
                    "network_scope": asset.get("network_scope"),
                    "ip_address": asset.get("current_ip"),
                    "mac_address": asset.get("mac_address"),
                    "classification": classification or "Unknown",
                    "decision": decision,
                    "confidence": confidence,
                    "evidence_count": evidence_count,
                    "contradiction_count": contradiction_count,
                    "reason": review_reason,
                    "priority": review_priority,
                }
            )

    top_classifications = [
        {
            "classification": classification,
            "count": count,
        }
        for classification, count in sorted(
            type_counts.items(),
            key=lambda item: (-item[1], item[0].lower()),
        )[:limit]
    ]

    review_queue = sorted(
        review_rows,
        key=lambda row: (
            row["priority"],
            row["confidence"],
            row["classification"].lower(),
            str(row.get("ip_address") or ""),
            str(row.get("asset_key") or ""),
        ),
    )[:limit]

    classified_percent = 0

    if total_assets:
        classified_percent = round((classified_assets / total_assets) * 100, 1)

    return {
        "total_assets": total_assets,
        "classified_assets": classified_assets,
        "possible_assets": possible_assets,
        "unknown_assets": unknown_assets,
        "evidence_backed_assets": evidence_backed_assets,
        "contradiction_assets": contradiction_assets,
        "high_confidence_assets": high_confidence_assets,
        "classified_percent": classified_percent,
        "top_classifications": top_classifications,
        "review_queue": review_queue,
    }


def dashboard_count(connection, table, where=None):
    sql = f"SELECT COUNT(*) AS count FROM {table}"

    if where:
        sql += f" WHERE {where}"

    try:
        row = connection.execute(sql).fetchone()
    except Exception:
        return 0

    if row is None:
        return 0

    return int(row["count"])


TELEMETRY_CLEANUP_CONFIRMATION = "DELETE TELEMETRY"

# These tables are intentionally preserved by telemetry cleanup. They contain
# access control, operator configuration, or user-authored context rather than
# imported scan evidence.
TELEMETRY_CLEANUP_PROTECTED_TABLES = {
    "access_users",
    "access_api_tokens",
    "access_sessions",
    "access_audit_log",
    "scan_schedules",
    "asset_annotations",
    "asset_annotation_history",
    "asset_investigations",
    "asset_investigation_history",
    "investigation_ticket_state",
    "investigation_ticket_history",
}

# Delete children/evidence first, then parent scan snapshots last.
TELEMETRY_CLEANUP_TABLES = [
    "validation_correlations",
    "validation_observations",
    "validation_runs",
    "netsniper_intelligence_hosts",
    "netsniper_intelligence_summaries",
    "trueaegis_jobs",
    "scan_jobs",
    "alert_notes",
    "alerts",
    "delta_events",
    "finding_observations",
    "service_observations",
    "asset_observations",
    "asset_lifecycle",
    "snapshots",
]


def telemetry_cleanup_table_exists(connection: sqlite3.Connection, table_name: str) -> bool:
    row = connection.execute(
        "SELECT name FROM sqlite_master WHERE type = 'table' AND name = ?",
        (table_name,),
    ).fetchone()
    return row is not None


def telemetry_cleanup_table_count(connection: sqlite3.Connection, table_name: str) -> int:
    if not telemetry_cleanup_table_exists(connection, table_name):
        return 0

    return int(
        connection.execute(f"SELECT COUNT(*) AS count FROM {table_name}").fetchone()["count"]
        or 0
    )


def telemetry_cleanup_counts(connection: sqlite3.Connection) -> dict[str, int]:
    return {
        table_name: telemetry_cleanup_table_count(connection, table_name)
        for table_name in TELEMETRY_CLEANUP_TABLES
    }


def telemetry_cleanup_protected_counts(connection: sqlite3.Connection) -> dict[str, int]:
    return {
        table_name: telemetry_cleanup_table_count(connection, table_name)
        for table_name in sorted(TELEMETRY_CLEANUP_PROTECTED_TABLES)
    }


def telemetry_cleanup_preview(connection: sqlite3.Connection) -> dict[str, Any]:
    counts = telemetry_cleanup_counts(connection)
    protected_counts = telemetry_cleanup_protected_counts(connection)

    return {
        "ok": True,
        "action": "telemetry.cleanup.preview",
        "dry_run": True,
        "confirmation_required": TELEMETRY_CLEANUP_CONFIRMATION,
        "tables": counts,
        "total_rows": sum(counts.values()),
        "protected_tables": protected_counts,
        "protected_total_rows": sum(protected_counts.values()),
        "message": (
            "Dry run only. Telemetry cleanup removes imported scan evidence while "
            "preserving users, sessions, API tokens, schedules, audit logs, and "
            "operator-authored annotations/investigation state."
        ),
    }


def telemetry_cleanup_clear_all(
    connection: sqlite3.Connection,
    confirmation: str,
    dry_run: bool = False,
) -> dict[str, Any]:
    before = telemetry_cleanup_counts(connection)
    protected_before = telemetry_cleanup_protected_counts(connection)

    if dry_run:
        return telemetry_cleanup_preview(connection)

    if str(confirmation or "").strip() != TELEMETRY_CLEANUP_CONFIRMATION:
        raise DeltaAegisError(
            f"telemetry cleanup requires confirmation phrase: {TELEMETRY_CLEANUP_CONFIRMATION}"
        )

    for table_name in TELEMETRY_CLEANUP_TABLES:
        if telemetry_cleanup_table_exists(connection, table_name):
            connection.execute(f"DELETE FROM {table_name}")

    after = telemetry_cleanup_counts(connection)
    protected_after = telemetry_cleanup_protected_counts(connection)

    changed = {
        table_name: before.get(table_name, 0) - after.get(table_name, 0)
        for table_name in TELEMETRY_CLEANUP_TABLES
    }

    return {
        "ok": True,
        "action": "telemetry.cleanup.clear_all",
        "dry_run": False,
        "confirmation_required": TELEMETRY_CLEANUP_CONFIRMATION,
        "tables_before": before,
        "tables_after": after,
        "deleted_rows": changed,
        "total_deleted_rows": sum(changed.values()),
        "protected_tables_before": protected_before,
        "protected_tables_after": protected_after,
        "protected_tables_preserved": protected_before == protected_after,
        "message": (
            "Telemetry cleanup completed. Access users, sessions, API tokens, "
            "schedules, audit logs, and operator-authored context were preserved."
        ),
    }





TELEMETRY_CLEANUP_AUDIT_ACTION = "TELEMETRY_CLEANUP_CLEAR_ALL"


def telemetry_cleanup_redact_audit_value(value: Any) -> Any:
    if isinstance(value, dict):
        redacted: dict[str, Any] = {}

        for key, child in value.items():
            lower_key = str(key).lower()

            if (
                "password" in lower_key
                or "token" in lower_key
                or "secret" in lower_key
                or "hash" in lower_key
            ):
                redacted[str(key)] = "[redacted]"
            else:
                redacted[str(key)] = telemetry_cleanup_redact_audit_value(child)

        return redacted

    if isinstance(value, list):
        return [telemetry_cleanup_redact_audit_value(child) for child in value]

    return value


def telemetry_cleanup_decode_json_object(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return value

    if not value:
        return {}

    if isinstance(value, str):
        decoded = decode_json_field(value, {})

        if isinstance(decoded, dict):
            return decoded

    return {}


def telemetry_cleanup_decode_audit_details(item: dict[str, Any]) -> dict[str, Any]:
    preferred_keys = (
        "details",
        "details_json",
        "metadata",
        "metadata_json",
        "context",
        "context_json",
        "data",
        "data_json",
    )

    for key in preferred_keys:
        decoded = telemetry_cleanup_decode_json_object(item.get(key))

        if decoded:
            return telemetry_cleanup_redact_audit_value(decoded)

    for key, value in item.items():
        lower_key = str(key).lower()

        if (
            "detail" not in lower_key
            and "metadata" not in lower_key
            and "context" not in lower_key
            and "json" not in lower_key
            and "data" not in lower_key
        ):
            continue

        decoded = telemetry_cleanup_decode_json_object(value)

        if decoded:
            return telemetry_cleanup_redact_audit_value(decoded)

    return {}


def telemetry_cleanup_audit_event_to_dict(row: sqlite3.Row | dict[str, Any]) -> dict[str, Any]:
    item = dict(row)
    details = telemetry_cleanup_decode_audit_details(item)
    item["details"] = details

    for key in list(item.keys()):
        lower_key = str(key).lower()

        if (
            "password" in lower_key
            or "token" in lower_key
            or "secret" in lower_key
            or "hash" in lower_key
        ):
            item[key] = "[redacted]"
            continue

        if (
            "detail" in lower_key
            or "metadata" in lower_key
            or "context" in lower_key
            or "json" in lower_key
            or "data" in lower_key
        ):
            decoded = telemetry_cleanup_decode_json_object(item.get(key))

            if decoded:
                item[key] = json.dumps(
                    telemetry_cleanup_redact_audit_value(decoded),
                    sort_keys=True,
                )

    return item


def query_telemetry_cleanup_audit_events(
    connection: sqlite3.Connection,
    limit: int = 20,
) -> list[sqlite3.Row]:
    safe_limit = max(1, min(int(limit or 20), 100))

    return connection.execute(
        """
        SELECT *
        FROM access_audit_log
        WHERE action = ?
        ORDER BY audit_id DESC
        LIMIT ?
        """,
        (TELEMETRY_CLEANUP_AUDIT_ACTION, safe_limit),
    ).fetchall()


def dashboard_telemetry_cleanup_audit_events_payload(
    connection: sqlite3.Connection,
    limit: int = 20,
) -> dict[str, Any]:
    safe_limit = max(1, min(int(limit or 20), 100))
    events = [
        telemetry_cleanup_audit_event_to_dict(row)
        for row in query_telemetry_cleanup_audit_events(
            connection,
            limit=safe_limit,
        )
    ]

    return {
        "ok": True,
        "action": "telemetry.cleanup.audit_events",
        "audit_action": TELEMETRY_CLEANUP_AUDIT_ACTION,
        "generated_at": utc_now_text(),
        "limit": safe_limit,
        "count": len(events),
        "events": events,
    }


def dashboard_telemetry_cleanup_preview_payload(
    connection: sqlite3.Connection,
) -> dict[str, Any]:
    return telemetry_cleanup_preview(connection)


def dashboard_telemetry_cleanup_clear_all_payload(
    connection: sqlite3.Connection,
    payload: dict[str, Any],
    actor: dict[str, Any] | None = None,
    source_ip: str | None = None,
    user_agent: str | None = None,
) -> dict[str, Any]:
    dry_run = dashboard_bool_from_payload(payload.get("dry_run"), False)
    confirmation = str(payload.get("confirmation") or "")

    result = telemetry_cleanup_clear_all(
        connection,
        confirmation=confirmation,
        dry_run=dry_run,
    )

    if not result.get("dry_run"):
        record_access_audit_event(
            connection,
            actor or {},
            action="TELEMETRY_CLEANUP_CLEAR_ALL",
            target_type="telemetry",
            target_key="all",
            source_ip=source_ip,
            user_agent=user_agent,
            details={
                "total_deleted_rows": result.get("total_deleted_rows", 0),
                "deleted_rows": result.get("deleted_rows", {}),
                "protected_tables_preserved": result.get("protected_tables_preserved"),
                "protected_tables_after": result.get("protected_tables_after", {}),
                "confirmation_phrase_required": TELEMETRY_CLEANUP_CONFIRMATION,
            },
        )

    result["receipt"] = dashboard_telemetry_cleanup_action_receipt(
        result
    )
    return result


